async function getOrCreateCategory(supabase: any, user_id: string, name: string, type: string) {
    const { data: existing } = await supabase
        .from('categories')
        .select('id')
        .eq('user_id', user_id)
        .eq('name', name)
        .eq('type', type)
        .single()

