export async function createTask(formData: FormData) {
    const supabase = await createClient()

    const title = formData.get('title') as string
    const priority = (formData.get('priority') as string) || 'Medium'
    const dueDateRaw = formData.get('due_date') as string
    const description = formData.get('description') as string

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) throw new Error('Unauthorized')

    const { data: task, error } = await supabase.from('tasks').insert({
        title,
        priority,
        due_date: dueDateRaw ? new Date(dueDateRaw).toISOString() : null,
        status: 'Todo',
        description,
        user_id: user.id
    }).select().single()

    if (error) {
        console.error('Error creating task:', error)
        throw new Error('Failed to create task')
    }

    revalidatePath('/dashboard/tasks')
    return { success: true, task }
}

export async function updateTaskStatus(id: string, status: string, completedAt?: string, reason?: string) {
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) throw new Error('Unauthorized')

    // Fetch task details to check for project linkage
    const { data: task } = await supabase
        .from('tasks')
        .select('title, project_id, team_id')
        .eq('id', id)
        .single()

    const updateData: any = { status }
    if (status === 'Done' && completedAt) {
        updateData.completed_at = completedAt
        updateData.completion_reason = reason
    } else if (status !== 'Done') {
        // Reset if moving back from Done
        updateData.completed_at = null
        updateData.completion_reason = null
    }

    const { error } = await supabase.from('tasks').update(updateData).eq('id', id)

    if (error) {
        console.error('Error updating task status:', error)
        throw new Error('Failed to update task status')
    }

    // If task is completed and linked to a project, send a notification message
    if (status === 'Done' && task?.project_id && task?.team_id) {
        try {
            await supabase.from('team_messages').insert({
                team_id: task.team_id,
                project_id: task.project_id,
                message: `Task completed: ${task.title}`,
                sender_id: user.id,
                type: 'system' // Optional: if we want to style it differently later, or just standard text
            })
        } catch (msgError) {
            console.error('Failed to send completion message:', msgError)
            // Don't fail the task update if message fails
        }
    }

    revalidatePath('/dashboard/tasks')
}

export async function deleteTask(id: string) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) throw new Error('Unauthorized')

    // Fetch task details before deletion to check assignment
    const { data: task } = await supabase
        .from('tasks')
        .select('title, team_id, project_id, assigned_to, user_id')
        .eq('id', id)
        .single()

    if (task) {
        // Check if task was assigned TO the current user BY someone else
        // task.assigned_to === user.id (Assigned to me)
        // task.user_id !== user.id (Created by someone else)
        if (task.assigned_to === user.id && task.user_id !== user.id && task.team_id) {
            console.log('Task rejection condition met. Sending message...')
            try {
                // Send automated rejection message
                const { error: msgInsertError } = await supabase.from('team_messages').insert({
                    team_id: task.team_id,
                    project_id: task.project_id,
                    message: `I will not do this task: ${task.title}`,
                    sender_id: user.id,
                    type: 'system' // or 'text', system might be better for styling if supported
                })

                if (msgInsertError) {
                    console.error('Message insert error detail:', msgInsertError)
                } else {
                    console.log('Message inserted successfully')
                }

                // Use Admin Client to delete (bypass RLS)
                const adminSupabase = createAdminClient()
                const { error: deleteError } = await adminSupabase.from('tasks').delete().eq('id', id)
                if (deleteError) throw deleteError

                revalidatePath('/dashboard/tasks')
                return // Exit early since we used admin client
            } catch (msgError) {
                console.error('Failed to handle assignee deletion/rejection:', msgError)
                // If admin delete failed, we might fall through or throw.
                // Throwing here is safer to indicate failure.
                throw new Error('Failed to delete assigned task')
            }
        }
    }

    // Standard delete (Own tasks / RLS allowed)
    // Fetch task details for message if not already fetched
    if (!task) {
        const { data: taskDetails } = await supabase
            .from('tasks')
            .select('title, team_id, project_id')
            .eq('id', id)
            .single()

        if (taskDetails && taskDetails.team_id) {
            try {
                await supabase.from('team_messages').insert({
                    team_id: taskDetails.team_id,
                    project_id: taskDetails.project_id,
                    message: `Task deleted: ${taskDetails.title}`,
                    sender_id: user.id,
                    type: 'system'
                })
            } catch (msgError) {
                console.error('Failed to send deletion message:', msgError)
            }
        }
    } else if (task.team_id) {
        try {
            await supabase.from('team_messages').insert({
                team_id: task.team_id,
                project_id: task.project_id,
                message: `Task deleted: ${task.title}`,
                sender_id: user.id,
                type: 'system'
            })
        } catch (msgError) {
            console.error('Failed to send deletion message:', msgError)
        }
    }

    const { error } = await supabase.from('tasks').delete().eq('id', id)
    if (error) throw new Error('Failed to delete task')

    revalidatePath('/dashboard/tasks')
}

export async function updateTask(id: string, formData: FormData) {
    const supabase = await createClient()

    const title = formData.get('title') as string
    const priority = (formData.get('priority') as string) || 'Medium'
    const dueDateRaw = formData.get('due_date') as string
    const description = formData.get('description') as string

    const { error } = await supabase.from('tasks')
        .update({
            title,
            priority,
            due_date: dueDateRaw ? new Date(dueDateRaw).toISOString() : null,
            description,
        })
        .eq('id', id)

    if (error) {
        console.error('Error updating task:', error)
        throw new Error('Failed to update task')
    }

    revalidatePath('/dashboard/tasks')
}

import { createClient } from '@/lib/supabase/server'
import { SharedItemsList } from '@/components/chat/SharedItemsList'
import { Hash, Share2 } from 'lucide-react'

interface SharedPageProps {
    params: Promise<{
        teamId: string
    }>
}

export default async function TeamSharedPage(props: SharedPageProps) {
    const params = await props.params;
    const { teamId } = params;
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return null

    // Get Team
    const { data: team } = await supabase
        .from('teams')
        .select('name')
        .eq('id', teamId)
        .single()

    if (!team) return <div>Team not found</div>

    // Fetch Shared Items with Details
    // This requires complex joining or multiple fetches.
    // Since Supabase join syntax on multiple foreign types is tricky inside distinct tables:
    // We'll fetch shared_items then fetch details.

    const { data: sharedItems } = await supabase
        .from('chat_shared_items')
        .select(`
            *,
            shared_by_user:users(name, avatar)
        `)
        .eq('team_id', teamId)
        .order('created_at', { ascending: false })

    // Fetch details for each item
    // Optimization: Group by type and fetch in batch

    if (!sharedItems) return <div>No shared items</div>

    const resourcesIds = sharedItems.filter(i => i.shared_type === 'resource').map(i => i.shared_item_id)
    const notesIds = sharedItems.filter(i => i.shared_type === 'note').map(i => i.shared_item_id)
    const pathIds = sharedItems.filter(i => i.shared_type === 'learning_path').map(i => i.shared_item_id)
    const roadmapIds = sharedItems.filter(i => i.shared_type === 'roadmap').map(i => i.shared_item_id)

    const [resourcesRes, notesRes, pathsRes, roadmapsRes] = await Promise.all([
        resourcesIds.length > 0 ? supabase.from('resources').select('*').in('id', resourcesIds) : { data: [] },
        notesIds.length > 0 ? supabase.from('notes').select('*').in('id', notesIds) : { data: [] },
        pathIds.length > 0 ? supabase.from('learning_paths').select('*').in('id', pathIds) : { data: [] },
        roadmapIds.length > 0 ? supabase.from('roadmaps').select('*').in('id', roadmapIds) : { data: [] }
    ])

    const resourcesMap = new Map((resourcesRes.data || []).map(i => [i.id, i]))
    const notesMap = new Map((notesRes.data || []).map(i => [i.id, i]))
    const pathsMap = new Map((pathsRes.data || []).map(i => [i.id, i]))
    const roadmapsMap = new Map((roadmapsRes.data || []).map(i => [i.id, i]))

    // Check if user has already added these items
    // We need to fetch user's items which have original_item_id in these sets.

    const allOriginalIds = sharedItems.map(i => i.shared_item_id)

    const [userResources, userNotes, userPaths, userRoadmaps] = await Promise.all([
        allOriginalIds.length > 0 ? supabase.from('resources').select('original_item_id').eq('user_id', user.id).not('original_item_id', 'is', null).in('original_item_id', allOriginalIds) : { data: [] },
        allOriginalIds.length > 0 ? supabase.from('notes').select('original_item_id').eq('user_id', user.id).not('original_item_id', 'is', null).in('original_item_id', allOriginalIds) : { data: [] },
        allOriginalIds.length > 0 ? supabase.from('learning_paths').select('original_item_id').eq('user_id', user.id).not('original_item_id', 'is', null).in('original_item_id', allOriginalIds) : { data: [] },
        allOriginalIds.length > 0 ? supabase.from('roadmaps').select('original_roadmap_id').eq('owner_id', user.id).not('original_roadmap_id', 'is', null).in('original_roadmap_id', allOriginalIds) : { data: [] }
    ])

    const addedSet = new Set([
        ...(userResources.data || []).map(i => i.original_item_id),
        ...(userNotes.data || []).map(i => i.original_item_id),
        ...(userPaths.data || []).map(i => i.original_item_id),
        ...(userRoadmaps.data || []).map(i => i.original_roadmap_id),
    ])

    const enrichedItems = sharedItems.map(item => {
        let details = {}
        if (item.shared_type === 'resource') details = resourcesMap.get(item.shared_item_id) || {}
        if (item.shared_type === 'note') details = notesMap.get(item.shared_item_id) || {}
        if (item.shared_type === 'learning_path') details = pathsMap.get(item.shared_item_id) || {}
        if (item.shared_type === 'roadmap') details = roadmapsMap.get(item.shared_item_id) || {}

        return {
            ...item,
            details,
            is_added: addedSet.has(item.shared_item_id)
        }
    }).filter(i => i.details && (i.details as any).title) // Filter out deleted originals

    return (
        <div className="flex flex-col h-full bg-background/50">
            <div className="h-14 border-b border-border flex items-center px-6 bg-card/50 backdrop-blur-sm shrink-0 gap-4">
                <div className="flex items-center gap-2 font-semibold text-foreground">
                    <Hash className="h-4 w-4 text-muted-foreground" />
                    {team.name}
                </div>
                <div className="h-4 w-px bg-border" />
                <div className="flex items-center gap-2 font-medium text-muted-foreground">
                    <Share2 className="h-4 w-4" />
                    Shared Content
                </div>
            </div>

            <SharedItemsList items={enrichedItems as any} teamId={teamId} />
        </div>
    )
}

'use server'

import { createClient, createAdminClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'
import { redirect } from 'next/navigation'

export async function createTeam(formData: FormData) {
    // We need normal client for auth check
    const supabase = await createClient()
    const name = formData.get('name') as string

    if (!name) {
        throw new Error('Team name is required')
    }

    const { data: { user }, error: authError } = await supabase.auth.getUser()
    if (authError || !user) {
        throw new Error('Unauthorized')
    }

    // Use Admin Client to bypass RLS for team creation if RPC is missing
    const adminClient = await createAdminClient()

    // 1. Create Team
    const { data: team, error: teamError } = await adminClient
        .from('teams')
        .insert({
            name,
            created_by: user.id
        })
        .select()
        .single()

    if (teamError) {
        console.error('Error creating team (Admin):', teamError)
        throw new Error('Failed to create team')
    }

    // 2. Add Member as Owner
    const { error: memberError } = await adminClient
        .from('team_members')
        .insert({
            team_id: team.id,
            user_id: user.id,
            role: 'owner'
        })

    if (memberError) {
        console.error('Error adding team member (Admin):', memberError)
        // Cleanup? If member add fails, we have an orphan team. 
        // Ideally we delete the team.
        await adminClient.from('teams').delete().eq('id', team.id)
        throw new Error('Failed to join team')
    }

    revalidatePath('/dashboard/chat')
    return team.id
}

export async function createProject(formData: FormData) {
    const supabase = await createClient()
    const name = formData.get('name') as string
    const teamId = formData.get('teamId') as string
    const membersJson = formData.get('members') as string

    let members: string[] = []
    try {
        members = membersJson ? JSON.parse(membersJson) : []
    } catch (e) {
        console.error("Failed to parse members", e)
    }

    if (!name || !teamId) {
        throw new Error('Project name and Team ID are required')
    }

    const { data: { user }, error: authError } = await supabase.auth.getUser()
    if (authError || !user) throw new Error('Unauthorized')

    // Start a transaction-like flow (Standard fetch doesn't support explicit transactions easily, we chain)
    const { data: project, error } = await supabase
        .from('projects')
        .insert({
            name,
            team_id: teamId,
            created_by: user.id
        })
        .select()
        .single()

    if (error) {
        console.error('Error creating project:', error)
        throw new Error('Failed to create project')
    }

    // Add creator to members automatically
    const membersToAdd = new Set([...members, user.id])

    const projectMembers = Array.from(membersToAdd).map(userId => ({
        project_id: project.id,
        user_id: userId,
        role: userId === user.id ? 'owner' : 'member'
    }))

    if (projectMembers.length > 0) {
        const { error: membersError } = await supabase
            .from('project_members')
            .insert(projectMembers)

        if (membersError) {
            console.error('Error adding project members:', membersError)
            // Non-fatal? Or fatal? Project exists but members missing.
            // We'll log it.
        }
    }

    revalidatePath('/dashboard/chat')
    revalidatePath(`/dashboard/chat/${teamId}`)
}

export async function addTeamMember(formData: FormData) {
    const supabase = await createClient()
    const email = formData.get('email') as string
    const teamId = formData.get('teamId') as string

    if (!email || !teamId) {
        return { success: false, error: 'Email and Team ID are required' }
    }

    // 1. Get User ID from email
    const { data: userToAdd, error: userError } = await supabase
        .from('users')
        .select('id')
        .eq('email', email)
        .single()

    if (userError || !userToAdd) {
        console.error('User not found:', email)
        return { success: false, error: 'User not found with this email' }
    }

    // 2. Add to team
    const { error } = await supabase
        .from('team_members')
        .insert({
            team_id: teamId,
            user_id: userToAdd.id,
            role: 'member'
        })

    if (error) {
        if (error.code === '23505') { // Unique violation
            return { success: true, message: 'User is already a member of this team.' }
        }
        console.error('Error adding member:', error)
        return { success: false, error: 'Failed to add member' }
    }

    revalidatePath('/dashboard/chat')
    return { success: true, message: 'Member added successfully.' }
}

export async function deleteTeam(teamId: string) {
    const supabase = await createClient()

    // RLS will handle permission checks (Owner only).
    const { error } = await supabase
        .from('teams')
        .delete()
        .eq('id', teamId)

    if (error) {
        console.error('Error deleting team:', error)
        throw new Error('Failed to delete team')
    }

    revalidatePath('/dashboard/chat')
}

export async function updateTeam(formData: FormData) {
    const supabase = await createClient()
    const teamId = formData.get('teamId') as string
    const name = formData.get('name') as string

    if (!teamId || !name) {
        throw new Error('Team ID and Name are required')
    }

    const { error } = await supabase
        .from('teams')
        .update({ name })
        .eq('id', teamId)

    if (error) {
        console.error('Error updating team:', error)
        throw new Error('Failed to update team')
    }

    revalidatePath('/dashboard/chat')
    revalidatePath(`/dashboard/chat/${teamId}`)
    revalidatePath(`/dashboard/chat/${teamId}`)
}

export async function updateMemberRole(teamId: string, userId: string, role: string) {
    const supabase = await createClient()

    if (!['owner', 'admin', 'member'].includes(role)) {
        throw new Error('Invalid role')
    }

    // Check if target user is the team creator
    const { data: team } = await supabase
        .from('teams')
        .select('created_by')
        .eq('id', teamId)
        .single()

    if (team?.created_by === userId) {
        throw new Error('Cannot change role of team creator')
    }

    const { error } = await supabase
        .from('team_members')
        .update({ role })
        .eq('team_id', teamId)
        .eq('user_id', userId)

    if (error) {
        console.error('Error updating member role:', error)
        throw new Error('Failed to update member role')
    }

    revalidatePath(`/dashboard/chat`)
}

export async function removeTeamMember(teamId: string, userId: string) {
    const supabase = await createClient()

    // Check if target user is the team creator
    const { data: team } = await supabase
        .from('teams')
        .select('created_by')
        .eq('id', teamId)
        .single()

    if (team?.created_by === userId) {
        throw new Error('Cannot remove team creator')
    }

    const { error } = await supabase
        .from('team_members')
        .delete()
        .eq('team_id', teamId)
        .eq('user_id', userId)

    if (error) {
        console.error('Error removing team member:', error)
        throw new Error('Failed to remove team member')
    }

    revalidatePath(`/dashboard/chat`)
}

export async function getTeamMembers(teamId: string) {
    const supabase = await createClient()

    // Get team creator
    const { data: team } = await supabase
        .from('teams')
        .select('created_by')
        .eq('id', teamId)
        .single()

    const { data, error } = await supabase
        .from('team_members')
        .select(`
            user_id,
            role,
            user:users(id, name, email, avatar)
        `)
        .eq('team_id', teamId)

    if (error) {
        console.error('Error fetching team members:', JSON.stringify(error, null, 2))
        throw new Error(`Failed to fetch team members: ${error.message}`)
    }

    return data.map(item => ({
        id: item.user_id,
        role: item.role,
        isCreator: team?.created_by === item.user_id,
        ...item.user
    }))
}

'use client'

import { useState } from 'react'
import { useSearchParams } from 'next/navigation'
import { signup } from '@/app/login/actions'
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Button } from '@/components/ui/button'
import Link from 'next/link'
import { signupSchema } from '@/lib/auth-schemas'
import { z } from 'zod'

export default function SignupPage() {
    const searchParams = useSearchParams()
    const serverError = searchParams.get('error')
    const [password, setPassword] = useState('')
    const [confirmPassword, setConfirmPassword] = useState('')
    const [error, setError] = useState<string | null>(null)
    const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({})

    // Client-side validation wrapper before hitting the server action
    const clientAction = async (formData: FormData) => {
        setError(null)
        setFieldErrors({})

        const rawData = {
            full_name: formData.get('full_name'),
            email: formData.get('email'),
            password: formData.get('password'),
            confirm_password: formData.get('confirm_password'),
            role: formData.get('role'),
        }

        const result = signupSchema.safeParse(rawData)

        if (!result.success) {
            const formattedErrors: Record<string, string> = {}
            result.error.issues.forEach((issue) => {
                const path = issue.path[0] as string
                formattedErrors[path] = issue.message
            })
            setFieldErrors(formattedErrors)

            if (formattedErrors.confirm_password) {
                setError(formattedErrors.confirm_password)
            } else if (Object.keys(formattedErrors).length > 0) {
                setError(Object.values(formattedErrors)[0])
            }
            return
        }

        // Trigger the server action
        await signup(formData)
    }

    return (
        <div className="min-h-screen flex items-center justify-center relative overflow-hidden bg-black p-4">
