                        Create Account
                    </CardTitle>
                    <CardDescription className="text-center text-zinc-400 text-base">
                        Join V today
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <form action={clientAction} className="space-y-5">
                        <div className="space-y-2">
                            <Label htmlFor="full_name" className="text-zinc-300">Full Name</Label>
                            <Input
                                id="full_name"
