    timestamp: Date
}

// ΓöÇΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function generateId() {
    return Math.random().toString(36).slice(2, 10)
}

// ΓöÇΓöÇΓöÇ Typing indicator ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function TypingDots() {
    return (
        <div className="flex items-center gap-1 px-1 py-0.5">
            {[0, 1, 2].map(i => (
                <motion.span
                    key={i}
                    className="block w-1.5 h-1.5 rounded-full bg-primary/60"
                    animate={{ opacity: [0.3, 1, 0.3], scale: [0.8, 1.1, 0.8] }}
                    transition={{ duration: 1.2, repeat: Infinity, delay: i * 0.2 }}
                />
            ))}
        </div>
    )
}

// ΓöÇΓöÇΓöÇ Message bubble ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function MessageBubble({ message, isStreaming, index }: { message: Message; isStreaming?: boolean; index: number }) {
    const isUser = message.role === 'user'
    return (
        <motion.div
            initial={{ opacity: 0, x: isUser ? 20 : -20, filter: 'blur(8px)' }}
            animate={{ opacity: 1, x: 0, filter: 'blur(0px)' }}
            transition={{
                duration: 0.5,
                delay: index * 0.05,
                ease: [0.21, 1.11, 0.81, 0.99] // Bouncy/Elastic feel
            }}
            className={cn('flex gap-3 items-end group', isUser && 'flex-row-reverse')}
        >
            {/* Avatar */}
            <div className={cn(
                'shrink-0 w-8 h-8 rounded-xl flex items-center justify-center transition-transform group-hover:scale-110',
                isUser
                    ? 'bg-primary/10 border border-primary/20 backdrop-blur-md'
                    : 'bg-gradient-to-tr from-violet-600 via-indigo-600 to-cyan-500 shadow-[0_0_15px_rgba(139,92,246,0.3)]'
            )}>
                {isUser
                    ? <User className="w-4 h-4 text-primary" />
                    : <img src="/branding/v1_icon.png" alt="V_1.0" className="w-full h-full object-cover rounded-xl" />
                }
            </div>

            {/* Content Container */}
            <div className={cn(
                'relative max-w-[85%] px-4 py-3 text-sm leading-relaxed shadow-sm',
                isUser
                    ? 'bg-primary text-primary-foreground rounded-2xl rounded-br-none font-medium'
                    : 'glass-dark border border-white/10 rounded-2xl rounded-bl-none text-foreground/90'
            )}>
                {/* Subtle internal glow for assistant messages */}
                {!isUser && (
                    <div className="absolute inset-0 rounded-2xl bg-gradient-to-br from-violet-500/5 to-transparent pointer-events-none" />
                )}

                {isStreaming && !message.content
                    ? <TypingDots />
                    : <span className="whitespace-pre-wrap relative z-10">{message.content}</span>
                }
                {isStreaming && message.content && (
                    <motion.span
                        className="inline-block w-1 h-4 bg-primary/80 ml-1.5 align-middle shadow-[0_0_8px_oklch(var(--primary))]"
                        animate={{ opacity: [1, 0] }}
                        transition={{ duration: 0.6, repeat: Infinity }}
                    />
                )}
            </div>
        </motion.div>
    )
}

// ΓöÇΓöÇΓöÇ Quick Action Chip ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function ActionChip({ label, onClick }: { label: string; onClick: () => void }) {
    return (
        <motion.button
            whileHover={{ scale: 1.05, y: -2 }}
            whileTap={{ scale: 0.95 }}
            onClick={onClick}
            className="px-4 py-2 rounded-xl text-[11px] font-semibold bg-white/5 hover:bg-white/10 border border-white/10 hover:border-primary/50 text-foreground/70 hover:text-foreground transition-all duration-300 cursor-pointer whitespace-nowrap backdrop-blur-sm shadow-sm"
        >
            {label}
        </motion.button>
    )
}

// ΓöÇΓöÇΓöÇ Main Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function AIAssistant() {
    const pathname = usePathname()
    const router = useRouter()
    const [isOpen, setIsOpen] = useState(false)
    const [messages, setMessages] = useState<Message[]>([])
    const [input, setInput] = useState('')
    const [isLoading, setIsLoading] = useState(false)
    const [streamingId, setStreamingId] = useState<string | null>(null)
    const [error, setError] = useState<string | null>(null)

    const scrollRef = useRef<HTMLDivElement>(null)
    const textareaRef = useRef<HTMLTextAreaElement>(null)
    const abortRef = useRef<AbortController | null>(null)

    const pageContext = getPageContext(pathname || '/dashboard')

    // Auto-scroll to bottom
    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight
        }
    }, [messages, isLoading])

    // Auto-resize textarea
    useEffect(() => {
        const el = textareaRef.current
        if (!el) return
        el.style.height = 'auto'
        el.style.height = Math.min(el.scrollHeight, 120) + 'px'
    }, [input])

    // Focus input when panel opens
    useEffect(() => {
        if (isOpen) {
            setTimeout(() => textareaRef.current?.focus(), 300)
        }
    }, [isOpen])

    // Reset quick actions when page changes
    useEffect(() => {
        // Clear error on page change
        setError(null)
    }, [pathname])

    const sendMessage = useCallback(async (text: string) => {
        const trimmed = text.trim()
        if (!trimmed || isLoading) return

        setError(null)
        setInput('')

        const userMsg: Message = {
            id: generateId(),
            role: 'user',
            content: trimmed,
            timestamp: new Date(),
        }

        const assistantId = generateId()
        const assistantMsg: Message = {
            id: assistantId,
            role: 'assistant',
            content: '',
            timestamp: new Date(),
        }

        setMessages(prev => [...prev, userMsg, assistantMsg])
        setIsLoading(true)
        setStreamingId(assistantId)

        // Build conversation history (exclude current empty assistant msg)
        const history = messages.map(m => ({ role: m.role, content: m.content }))

        try {
            abortRef.current = new AbortController()

            const response = await fetch('/api/ai-assistant', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    message: trimmed,
                    pageContext,
                    conversationHistory: history,
                }),
                signal: abortRef.current.signal,
            })

            if (!response.ok) {
                const err = await response.json().catch(() => ({ error: 'Unknown error' }))
                throw new Error(err.error || 'Failed to get response')
            }

            const contentType = response.headers.get('Content-Type') || ''

            if (contentType.includes('application/json')) {
                const data = await response.json()
                if (data.type === 'tool_result') {
                    // Update the message content first
                    setMessages(prev => prev.map(m =>
                        m.id === assistantId ? { ...m, content: data.result } : m
                    ))

                    // Handle specific actions
                    if (data.action === 'navigate') {
                        setTimeout(() => {
                            router.push(data.path)
                            setIsOpen(false)
                        }, 800)
                    } else if (data.action === 'refresh') {
                        router.refresh()
                    }
                } else if (data.type === 'error') {
                    throw new Error(data.message)
                }
                setIsLoading(false)
                setStreamingId(null)
                return
            }

            // Stream the response
            const reader = response.body?.getReader()
            if (!reader) throw new Error('No response stream')

            const decoder = new TextDecoder()
            let fullContent = ''

            while (true) {
                const { done, value } = await reader.read()
                if (done) break

                const chunk = decoder.decode(value, { stream: true })
                fullContent += chunk

                setMessages(prev =>
                    prev.map(m =>
                        m.id === assistantId ? { ...m, content: fullContent } : m
                    )
                )
            }
        } catch (err: any) {
            if (err.name === 'AbortError') return

            const errorText = err.message || 'Something went wrong. Please try again.'
            setError(errorText)

            // Update the assistant message with error
            setMessages(prev =>
                prev.map(m =>
                    m.id === assistantId
                        ? { ...m, content: `Γ¥î ${errorText}` }
                        : m
                )
            )
        } finally {
            setIsLoading(false)
            setStreamingId(null)
        }
    }, [isLoading, messages, pageContext])

    const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault()
            sendMessage(input)
        }
    }

    const handleClearChat = () => {
        abortRef.current?.abort()
        setMessages([])
        setError(null)
        setIsLoading(false)
        setStreamingId(null)
    }

    const isEmpty = messages.length === 0

    return (
        <>
            {/* ΓöÇΓöÇ Floating Trigger Button ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
            <motion.button
                onClick={() => setIsOpen(prev => !prev)}
                className={cn(
                    'fixed bottom-8 right-8 z-50',
                    'w-16 h-16 rounded-[24px]',
                    'flex items-center justify-center',
                    'bg-gradient-to-tr from-violet-600 via-indigo-600 to-cyan-500',
                    'shadow-[0_8px_30px_rgb(139,92,246,0.35)]',
                    'border border-white/20',
                    'hover:shadow-[0_8px_40px_rgb(139,92,246,0.5)] transition-all duration-500',
                    'mb-safe'
                )}
                whileHover={{ scale: 1.08, rotate: isOpen ? -90 : 5 }}
                whileTap={{ scale: 0.92 }}
                title="V_1.0 Assistant"
                aria-label="Open V_1.0 Assistant"
            >
                <div className="absolute inset-0 bg-white/10 opacity-0 hover:opacity-100 transition-opacity rounded-[24px]" />
                <AnimatePresence mode="wait">
                    {isOpen ? (
                        <motion.div
                            key="close"
                            initial={{ opacity: 0, scale: 0.5 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.5 }}
                            transition={{ duration: 0.2 }}
                        >
                            <X className="w-6 h-6 text-white" />
                        </motion.div>
                    ) : (
                        <motion.div
                            key="open"
                            initial={{ opacity: 0, scale: 0.5 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.5 }}
                            transition={{ duration: 0.2 }}
                            className="w-8 h-8 pointer-events-none"
                        >
                            <img src="/branding/v1_icon.png" alt="V_1.0" className="w-full h-full object-cover rounded-lg" />
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* Atmospheric Glow Ring */}
                {!isOpen && (
                    <motion.span
                        className="absolute inset-[-4px] rounded-[28px] border border-violet-500/30"
                        animate={{ scale: [1, 1.15, 1], opacity: [0.8, 0.2, 0.8] }}
                        transition={{ duration: 3, repeat: Infinity, ease: 'easeInOut' }}
                    />
                )}
                {!isOpen && (
                    <motion.span
                        className="absolute inset-0 rounded-[24px] shadow-[0_0_25px_oklch(var(--primary)/0.4)]"
                        animate={{ opacity: [0.5, 1, 0.5] }}
                        transition={{ duration: 2, repeat: Infinity }}
                    />
                )}
            </motion.button>

            {/* ΓöÇΓöÇ Slide-Up Panel ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, y: 40, scale: 0.9, filter: 'blur(20px)' }}
                        animate={{ opacity: 1, y: 0, scale: 1, filter: 'blur(0px)' }}
                        exit={{ opacity: 0, y: 40, scale: 0.9, filter: 'blur(20px)' }}
                        transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
                        className={cn(
                            'fixed z-50',
                            // Responsive Positioning & Sizing
                            'bottom-0 right-0 w-full h-full rounded-none', // XS/S: Full screen
                            'sm:bottom-24 sm:right-8 sm:w-[420px] sm:h-auto sm:max-h-[min(700px,calc(100vh-10rem))] sm:rounded-[32px]', // MD: Standard
                            'lg:w-[480px] lg:max-h-[min(800px,calc(100vh-12rem))] lg:rounded-[40px]', // L: Large
                            'xl:w-[540px] xl:right-12 xl:bottom-32 xl:rounded-[48px]', // XL: Ultra-luxury

                            'overflow-hidden flex flex-col',
                            'border border-white/10',
                            'glass-dark saturate-150 shadow-[0_20px_60px_rgba(0,0,0,0.6)]',
                        )}
                    >
                        {/* Interactive Background Grain & Mesh */}
                        <div className="absolute inset-0 pointer-events-none opacity-[0.04] bg-[url('https://grainy-gradients.vercel.app/noise.svg')]" />
                        <div className="absolute -top-[20%] -right-[20%] w-[60%] h-[60%] bg-violet-500/10 blur-[100px] pointer-events-none rounded-full" />
                        <div className="absolute -bottom-[20%] -left-[20%] w-[60%] h-[60%] bg-cyan-500/10 blur-[100px] pointer-events-none rounded-full" />
                        {/* ΓöÇΓöÇ Header ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                        <div className="flex items-center justify-between px-6 py-5 border-b border-white/5 shrink-0 bg-white/5 backdrop-blur-md">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-xl overflow-hidden flex items-center justify-center shadow-lg border border-white/10">
                                    <img src="/branding/v1_icon.png" alt="V_1.0 Logo" className="w-full h-full object-cover" />
                                </div>
                                <div>
                                    <p className="text-base font-bold text-foreground tracking-tight sm:text-lg">V_1.0</p>
                                    <p className="text-[11px] text-muted-foreground/80 leading-none font-medium mt-1">
                                        Luxury Intelligence ┬╖ {pageContext.page}
                                    </p>
                                </div>
                            </div>
                            <div className="flex items-center gap-1">
                                {messages.length > 0 && (
                                    <button
                                        onClick={handleClearChat}
                                        className="p-1.5 rounded-lg hover:bg-muted/60 text-muted-foreground hover:text-foreground transition-colors"
                                        title="Clear chat"
                                    >
                                        <RefreshCw className="w-3.5 h-3.5" />
                                    </button>
                                )}
                                <button
                                    onClick={() => setIsOpen(false)}
                                    className="p-1.5 rounded-lg hover:bg-muted/60 text-muted-foreground hover:text-foreground transition-colors"
                                >
                                    <X className="w-3.5 h-3.5" />
                                </button>
                            </div>
                        </div>

                        {/* ΓöÇΓöÇ Messages Area ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                        <div
                            ref={scrollRef}
                            className="flex-1 overflow-y-auto px-6 py-6 space-y-6 min-h-0 scroll-smooth overscroll-contain"
                            style={{
                                scrollbarWidth: 'thin',
                                WebkitOverflowScrolling: 'touch' // iOS Momentum Scrolling
                            }}
                        >
                            {/* Empty state ΓÇö welcome message */}
                            {isEmpty && (
                                <motion.div
                                    initial={{ opacity: 0, y: 8 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    className="text-center pt-4 pb-2"
                                >
                                    <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-violet-500/20 to-indigo-500/20 border border-violet-500/20 flex items-center justify-center mx-auto mb-3">
                                        <Zap className="w-5 h-5 text-violet-400" />
                                    </div>
                                    <p className="text-sm font-medium text-foreground">
                                        Ask me anything about your {pageContext.page}
                                    </p>
                                    <p className="text-xs text-muted-foreground mt-1 leading-relaxed px-4">
                                        {pageContext.hint}
                                    </p>
                                </motion.div>
                            )}

                            {/* Message list */}
                            {messages.map((msg, idx) => (
                                <MessageBubble
                                    key={msg.id}
                                    message={msg}
                                    index={idx}
                                    isStreaming={streamingId === msg.id}
                                />
                            ))}
                        </div>

                        {/* ΓöÇΓöÇ Quick Action Chips ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                        {isEmpty && (
                            <div className="px-4 pb-3 shrink-0">
                                <div className="flex flex-wrap gap-1.5">
                                    {pageContext.quickActions.slice(0, 4).map(action => (
                                        <ActionChip
                                            key={action}
                                            label={action}
                                            onClick={() => sendMessage(action)}
                                        />
                                    ))}
                                </div>
                            </div>
                        )}

                        <div className="px-6 pb-6 shrink-0 border-t border-white/5 pt-6 bg-white/5 backdrop-blur-xl">
                            {error && (
                                <p className="text-xs text-destructive/90 font-medium mb-3 px-1.5 flex items-center gap-2">
                                    <span className="w-1.5 h-1.5 rounded-full bg-destructive animate-pulse" />
                                    {error}
                                </p>
                            )}
                            <div className="relative group">
                                <div className="absolute -inset-1 bg-gradient-to-r from-violet-600 to-indigo-600 rounded-[24px] opacity-0 group-focus-within:opacity-15 transition-opacity duration-700 blur-xl" />
                                <div className="relative flex items-end gap-3 bg-white/5 border border-white/10 rounded-[24px] px-5 py-4 focus-within:border-primary/40 focus-within:bg-white/10 transition-all duration-500 shadow-inner">
                                    <textarea
                                        ref={textareaRef}
                                        value={input}
                                        onChange={e => setInput(e.target.value)}
                                        onKeyDown={handleKeyDown}
                                        placeholder={`Consult with V_1.0...`}
                                        rows={1}
                                        disabled={isLoading}
                                        className="flex-1 bg-transparent text-[15px] text-foreground placeholder:text-muted-foreground/50 resize-none outline-none leading-relaxed min-h-[26px] max-h-[160px] scrollbar-thin disabled:opacity-50 font-medium"
                                    />
                                    <motion.button
                                        onClick={() => sendMessage(input)}
                                        disabled={!input.trim() || isLoading}
                                        whileHover={{ scale: 1.1, rotate: input.trim() ? -5 : 0 }}
                                        whileTap={{ scale: 0.9 }}
                                        className={cn(
                                            'shrink-0 w-11 h-11 rounded-2xl flex items-center justify-center transition-all duration-500',
                                            input.trim() && !isLoading
                                                ? 'bg-gradient-to-tr from-violet-600 to-indigo-600 text-white shadow-[0_4px_15px_rgba(139,92,246,0.3)] cursor-pointer'
                                                : 'bg-white/5 text-muted-foreground/30 cursor-not-allowed'
                                        )}
                                    >
                                        {isLoading
                                            ? <Loader2 className="w-5 h-5 animate-spin" />
                                            : <Send className="w-5 h-5" />
                                        }
                                    </motion.button>
                                </div>
                            </div>
                            <p className="text-[11px] text-muted-foreground/40 mt-3 text-center font-medium tracking-wide">
                                PROMPT V_1.0 ┬╖ SHIFT+ENTER FOR NEW LINE
                            </p>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </>
    )
}

"use client"

import { cn } from "@/lib/utils"
import { useEffect, useRef, useState } from "react"
import Image from "next/image"

interface BackgroundWrapperProps {
    deviceType: 'mobile' | 'tablet' | 'desktop'
    customUrl?: string | null
    children?: React.ReactNode
}

export function BackgroundWrapper({ deviceType, customUrl, children }: BackgroundWrapperProps) {
    const [imgElement, setImgElement] = useState<HTMLImageElement | null>(null)

    useEffect(() => {
        if (!customUrl || !imgElement) {
            // Reset to defaults if no custom background
            if (!customUrl) {
                const vars = ['--card', '--popover', '--sidebar', '--muted', '--foreground', '--card-foreground', '--popover-foreground', '--sidebar-foreground', '--muted-foreground']
                vars.forEach(v => document.documentElement.style.removeProperty(v))
            }
            return
        }

        const applyTheme = async () => {
            try {
                // Lazy load ColorThief to reduce initial bundle size
                const ColorThief = (await import('colorthief')).default
                const colorThief = new ColorThief()

                // Execute heavy work in idle time to avoid blocking UI
                requestIdleCallback(() => {
                    if (imgElement.complete) {
                        try {
                            const color = colorThief.getColor(imgElement)
                            if (color) {
                                const [r, g, b] = color

                                // Set Variables
                                document.documentElement.style.setProperty('--card', `rgba(${r}, ${g}, ${b}, 0.2)`)
                                document.documentElement.style.setProperty('--popover', `rgba(${r}, ${g}, ${b}, 0.2)`)
                                document.documentElement.style.setProperty('--sidebar', `rgba(${r}, ${g}, ${b}, 0.15)`)
                                document.documentElement.style.setProperty('--muted', `rgba(${r}, ${g}, ${b}, 0.1)`)

                                // Contrast Logic
                                const brightness = (r * 299 + g * 587 + b * 114) / 1000
                                if (brightness > 128) {
                                    // Light Background -> Dark Text
                                    const darkText = 'oklch(0.145 0 0)'
                                    const darkMuted = 'oklch(0.40 0 0)'
                                    document.documentElement.style.setProperty('--foreground', darkText)
                                    document.documentElement.style.setProperty('--card-foreground', darkText)
                                    document.documentElement.style.setProperty('--popover-foreground', darkText)
                                    document.documentElement.style.setProperty('--sidebar-foreground', darkText)
                                    document.documentElement.style.setProperty('--muted-foreground', darkMuted)
                                } else {
                                    // Dark Background -> Light Text
                                    const lightText = 'oklch(0.985 0 0)'
                                    const lightMuted = 'oklch(0.708 0 0)'
                                    document.documentElement.style.setProperty('--foreground', lightText)
                                    document.documentElement.style.setProperty('--card-foreground', lightText)
                                    document.documentElement.style.setProperty('--popover-foreground', lightText)
                                    document.documentElement.style.setProperty('--sidebar-foreground', lightText)
                                    document.documentElement.style.setProperty('--muted-foreground', lightMuted)
                                }
                            }
                        } catch (e) {
                            console.error("Color extraction failed:", e)
                        }
                    }
                })
            } catch (e) {
                console.error("Failed to load ColorThief:", e)
            }
        }

        if (imgElement.complete) {
            applyTheme()
        } else {
            imgElement.addEventListener('load', applyTheme)
        }

        return () => {
            imgElement.removeEventListener('load', applyTheme)
        }
    }, [customUrl, imgElement])

    return (
        <>
            <div className="fixed inset-0 -z-10 overflow-hidden pointer-events-none">
                {/* Custom Background Override */}
                {customUrl && (
                    <div className="absolute inset-0">
                        <Image
                            src={customUrl}
                            alt="Background"
                            fill
                            className="object-cover transition-opacity duration-700"
                            priority={true}
                            quality={deviceType === 'mobile' ? 60 : 80}
                            onLoad={(e) => setImgElement(e.currentTarget)}
                            unoptimized={true}
                            crossOrigin="anonymous"
                        />
                        <div className="absolute inset-0 bg-black/20" />
                    </div>
                )}

                {!customUrl && (
                    <>
                        {/* Desktop Background - Luxury Aurora/Mesh Gradient */}
                        {deviceType === 'desktop' && (
                            <div className="absolute inset-0 bg-[#050505]">
                                <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] rounded-full bg-indigo-600/20 blur-[120px] animate-blob" />
                                <div className="absolute bottom-[-20%] right-[-10%] w-[60%] h-[60%] rounded-full bg-purple-600/20 blur-[120px] animate-blob animation-delay-2000" />
                                <div className="absolute top-[20%] left-[30%] w-[40%] h-[40%] rounded-full bg-cyan-600/10 blur-[120px] animate-blob animation-delay-4000" />

                                {/* Texture & Overlay */}
                                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-[0.15] mix-blend-soft-light pointer-events-none" />
                                <div className="absolute inset-0 bg-gradient-to-tr from-black/40 via-transparent to-black/40" />
                            </div>
                        )}

                        {/* Mobile/Tablet Background - Simplified, Vertical Luxury */}
                        {(deviceType === 'mobile' || deviceType === 'tablet') && (
                            <div className="absolute inset-0 bg-[#050505]">
                                <div className="absolute top-0 left-0 w-full h-[50%] bg-gradient-to-b from-indigo-900/20 to-transparent blur-[60px] animate-pulse" />
                                <div className="absolute bottom-0 right-0 w-full h-[50%] bg-gradient-to-t from-purple-900/20 to-transparent blur-[60px] animate-pulse delay-1000" />
                                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-[0.1] mix-blend-soft-light" />
                            </div>
                        )}

                        {/* Light Mode Override - Modernized */}
                        <div className="dark:hidden absolute inset-0 bg-slate-50">
                            <div className="absolute top-[-10%] left-[-10%] w-[60%] h-[60%] rounded-full bg-indigo-100/50 blur-[100px] animate-blob" />
                            <div className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] rounded-full bg-purple-100/50 blur-[100px] animate-blob animation-delay-2000" />
                            <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-[0.05] mix-blend-multiply" />
                        </div>
                    </>
                )}
            </div>
            {children}
        </>
    )
}

'use client'

import { useState } from 'react'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { addTeamMember } from '@/app/dashboard/teams/actions'
import { UserPlus, Loader2 } from 'lucide-react'
import { DropdownMenuItem } from '@/components/ui/dropdown-menu'

interface AddMemberDialogProps {
    teamId: string
    open?: boolean
    onOpenChange?: (open: boolean) => void
}

export function AddMemberDialog({ teamId, open, onOpenChange }: AddMemberDialogProps) {
    // If controlled, use parent state, else local. 
    // Simplified: Just use local for now, but usually it's triggered from a Dropdown so we need to handle open state carefully or use the Dialog directly.
    // Actually, DropdownMenuItem closing conflicts with Dialog open. 
    // Best pattern: The DialogTrigger is INSIDE the DropdownMenu? No, that closes the menu.
    // We should separate them or use the "select to open" pattern.

    // Changing approach: This component will be the Dialog itself. The Trigger is handled by the caller or passed as child?
    // Let's make it usable as a standalone button OR controlled.

    // For simplicity in Sidebar, let's just make it a Dialog that renders a Trigger.
    // If valid trigger is passed, use it.

    const [internalOpen, setInternalOpen] = useState(false)
    const [email, setEmail] = useState('')
    const [isLoading, setIsLoading] = useState(false)
    const [message, setMessage] = useState('')

    const isOpen = open !== undefined ? open : internalOpen
    const setOpen = onOpenChange || setInternalOpen

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!email.trim()) return

        setIsLoading(true)
        setMessage('')

        try {
            const formData = new FormData()
            formData.append('email', email)
            formData.append('teamId', teamId)
            const result = await addTeamMember(formData)

            if (result.success) {
                // Optionally show success message before closing? 
                // For now, just close as before, but maybe log or toast?
                setOpen(false)
                setEmail('')
            } else {
                setMessage(result.error || 'Failed to add member.')
            }
        } catch (error) {
            console.error('Failed to add member:', error)
            setMessage('An unexpected error occurred.')
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <Dialog open={isOpen} onOpenChange={setOpen}>
            <DialogContent className="sm:max-w-[425px]">
                <DialogHeader>
                    <DialogTitle>Add Team Member</DialogTitle>
                    <DialogDescription>
                        Invite a user to your team by their email address.
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit}>
                    <div className="grid gap-4 py-4">
                        <div className="grid grid-cols-4 items-center gap-4">
                            <Label htmlFor="email" className="text-right">
                                Email
                            </Label>
                            <Input
                                id="email"
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                className="col-span-3"
                                placeholder="user@example.com"
                                disabled={isLoading}
                                autoFocus
                            />
                        </div>
                        {message && <p className="text-sm text-destructive text-center">{message}</p>}
                    </div>
                    <DialogFooter>
                        <Button type="submit" disabled={isLoading || !email.trim()}>
                            {isLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                            Add Member
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState } from 'react'
import { Paperclip, Book, FileText, TrendingUp, GraduationCap, X, Map as MapIcon } from 'lucide-react'
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from '@/components/ui/popover'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import { createClient } from '@/lib/supabase/client'

type AttachmentType = 'resource' | 'note' | 'finance' | 'learning_path' | 'roadmap'

interface AttachmentPickerProps {
    onSelect: (type: AttachmentType, item: any) => void
    projectId?: string
}

export function AttachmentPicker({ onSelect, projectId }: AttachmentPickerProps) {
    const [open, setOpen] = useState(false)
    const [pickerType, setPickerType] = useState<AttachmentType | null>(null)
    const [items, setItems] = useState<any[]>([])
    const [loading, setLoading] = useState(false)

    const handleTypeSelect = async (type: AttachmentType) => {
        if (type === 'finance') {
            if (projectId) {
                onSelect('finance', { id: projectId, title: 'Project Finance Overview' })
                setOpen(false)
                return
            }
            setPickerType('finance')
            await fetchItems('finance')
        } else {
            setPickerType(type)
            await fetchItems(type)
        }
    }

    const fetchItems = async (type: AttachmentType) => {
        setLoading(true)
        const supabase = createClient()
        let data: any[] = []

        try {
            if (type === 'resource') {
                const { data: resources } = await supabase.from('resources').select('id, title, project_id').limit(20)
                data = resources || []
            } else if (type === 'note') {
                const { data: notes } = await supabase.from('notes').select('id, title, project_id').limit(20)
                data = notes || []
            } else if (type === 'learning_path') {
                const { data: paths } = await supabase.from('learning_paths').select('id, title, project_id').limit(20)
                data = paths || []
            } else if (type === 'finance') {
                const { data: projects } = await supabase.from('projects').select('id, name')
                data = projects?.map(p => ({ id: p.id, title: p.name, project_id: p.id })) || []
            } else if (type === 'roadmap') {
                const { data: roadmaps } = await supabase.from('roadmaps').select('id, title, project_id').limit(20)
                data = roadmaps || []
            }
        } catch (error) {
            console.error('Failed to fetch items', error)
        } finally {
            setItems(data)
            setLoading(false)
        }
    }

    const handleItemSelect = (item: any) => {
        onSelect(pickerType!, item)
        setOpen(false)
        setPickerType(null)
    }

    return (
        <>
            <Popover open={open} onOpenChange={setOpen}>
                <PopoverTrigger asChild>
                    <Button variant="ghost" size="icon" className="h-8 w-8 rounded-full text-muted-foreground hover:text-foreground">
                        <Paperclip className="h-5 w-5" />
                    </Button>
                </PopoverTrigger>
                <PopoverContent className="w-56 p-2" align="start">
                    <div className="grid grid-cols-1 gap-1">
                        <Button variant="ghost" className="justify-start font-normal" onClick={() => handleTypeSelect('resource')}>
                            <Book className="mr-2 h-4 w-4" />
                            Share Resource
                        </Button>
                        <Button variant="ghost" className="justify-start font-normal" onClick={() => handleTypeSelect('note')}>
                            <FileText className="mr-2 h-4 w-4" />
                            Share Note
                        </Button>
                        <Button variant="ghost" className="justify-start font-normal" onClick={() => handleTypeSelect('learning_path')}>
                            <GraduationCap className="mr-2 h-4 w-4" />
                            Share Learning Path
                        </Button>
                        <Button variant="ghost" className="justify-start font-normal" onClick={() => handleTypeSelect('finance')}>
                            <TrendingUp className="mr-2 h-4 w-4" />
                            Share Finance
                        </Button>
                        <Button variant="ghost" className="justify-start font-normal" onClick={() => handleTypeSelect('roadmap')}>
                            <MapIcon className="mr-2 h-4 w-4" />
                            Share Roadmap
                        </Button>
                    </div>
                </PopoverContent>
            </Popover>

            <Dialog open={!!pickerType} onOpenChange={(val) => !val && setPickerType(null)}>
                <DialogContent className="sm:max-w-[425px] p-0 gap-0 overflow-hidden">
                    <DialogHeader className="p-4 pb-2 border-b">
                        <DialogTitle>
                            Select {pickerType === 'resource' ? 'Resource' :
                                pickerType === 'note' ? 'Note' :
                                    pickerType === 'learning_path' ? 'Learning Path' :
                                        pickerType === 'roadmap' ? 'Roadmap' : 'Project'}
                        </DialogTitle>
                    </DialogHeader>
                    <div className="p-2 border-b">
                        <Input
                            placeholder="Search..."
                            className="border-none shadow-none focus-visible:ring-0"
                            autoFocus
                        />
                    </div>
                    <div className="max-h-[300px] overflow-y-auto p-1">
                        {items.length === 0 && !loading && (
                            <div className="py-6 text-center text-sm text-muted-foreground">
                                No results found.
                            </div>
                        )}
                        {loading && (
                            <div className="py-6 text-center text-sm text-muted-foreground">
                                Loading...
                            </div>
                        )}
                        <div className="grid gap-1">
                            {items.map((item) => (
                                <button
                                    key={item.id}
                                    className="flex w-full items-center rounded-sm px-2 py-1.5 text-sm outline-none hover:bg-accent hover:text-accent-foreground cursor-pointer text-left"
                                    onClick={() => handleItemSelect(item)}
                                >
                                    {pickerType === 'resource' && <Book className="mr-2 h-4 w-4 opacity-50" />}
                                    {pickerType === 'note' && <FileText className="mr-2 h-4 w-4 opacity-50" />}
                                    {pickerType === 'learning_path' && <GraduationCap className="mr-2 h-4 w-4 opacity-50" />}
                                    {pickerType === 'finance' && <TrendingUp className="mr-2 h-4 w-4 opacity-50" />}
                                    {pickerType === 'roadmap' && <MapIcon className="mr-2 h-4 w-4 opacity-50" />}
                                    {item.title}
                                </button>
                            ))}
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </>
    )
}

'use client'

import { TypingIndicator } from './TypingIndicator'
import { useEffect, useRef, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabase/client'
import { Message } from './MessageItem'
import { MessageList } from './MessageList'
import { ChatInput } from './ChatInput'
import { sendMessage, markProjectMessagesAsRead } from '@/app/dashboard/chat/actions'
import { v4 as uuidv4 } from 'uuid'
import { toast } from 'sonner'
import { differenceInMinutes } from 'date-fns'
import { ConnectionStatus } from './ConnectionStatus'

interface ChatContainerProps {
    initialMessages: Message[]
    teamId: string
    projectId?: string
    currentUser: {
        id: string
        name: string
        avatar: string
        email: string
    }
    members: any[]
}

type RealtimeStatus = 'connected' | 'reconnecting' | 'disconnected'

export function ChatContainer({ initialMessages, teamId, projectId, currentUser, members }: ChatContainerProps) {
    // Enrich messages with read tracking
    const [messages, setMessages] = useState<Message[]>(initialMessages)
    const [status, setStatus] = useState<RealtimeStatus>('connected')
    const [typingUsers, setTypingUsers] = useState<Map<string, { name: string, until: number }>>(new Map())
    const supabase = useState(() => createClient())[0]

    const totalMembers = members.length

    // Mark messages as read when entering the chat
    useEffect(() => {
        markProjectMessagesAsRead(teamId, projectId || null)
    }, [teamId, projectId])

    // Clear expired typing users
    useEffect(() => {
        const interval = setInterval(() => {
            const now = Date.now()
            setTypingUsers(prev => {
                const next = new Map(prev)
                let changed = false
                for (const [id, data] of next.entries()) {
                    if (data.until < now) {
                        next.delete(id)
                        changed = true
                    }
                }
                return changed ? next : prev
            })
        }, 1000)
        return () => clearInterval(interval)
    }, [])

    const handleBroadcastTyping = useCallback(async () => {
        const channel = supabase.channel(`chat:${teamId}:${projectId || 'team'}`)
        await channel.send({
            type: 'broadcast',
            event: 'typing',
            payload: {
                userId: currentUser.id,
                name: currentUser.name
            }
        })
    }, [teamId, projectId, currentUser, supabase])

    // Optimistic Update Handler
    const handleSendMessage = async (formData: FormData) => {
        const messageText = formData.get('message') as string
        const metadataRaw = formData.get('metadata') as string
        let metadata = null
        try {
            if (metadataRaw) metadata = JSON.parse(metadataRaw)
        } catch { }

        // 1. Create Optimistic Message
        const optimisticId = uuidv4()
        const optimisticMessage: Message = {
            id: optimisticId,
            team_id: teamId,
            project_id: projectId || null,
            sender_id: currentUser.id,
            message: messageText,
            created_at: new Date().toISOString(),
            sender: {
                name: currentUser.name,
                avatar: currentUser.avatar,
                email: currentUser.email
            },
            is_sender: true,
            read_status: 'sent',
            metadata: metadata,
            message_reads: [] // Initialize empty reads
        }

        // 2. Add to State Immediately
        setMessages(prev => [...prev, optimisticMessage])

        try {
            // 3. Call Server Action
            await sendMessage(formData)
        } catch (error) {
            console.error('Failed to send message:', error)
            toast.error('Failed to send message')
            // 4. Rollback on failure
            setMessages(prev => prev.filter(m => m.id !== optimisticId))
        }
    }

    // Realtime Subscription
    const currentUserRef = useRef(currentUser)
    const membersRef = useRef(members)
    const totalMembersRef = useRef(totalMembers)

    useEffect(() => {
        currentUserRef.current = currentUser
        membersRef.current = members
        totalMembersRef.current = totalMembers
    }, [currentUser, members, totalMembers])

    useEffect(() => {
        const channel = supabase
            .channel(`chat:${teamId}:${projectId || 'team'}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'team_messages',
                    filter: `team_id=eq.${teamId}`
                },
                async (payload) => {
                    if (payload.eventType === 'INSERT') {
                        const newMessage = payload.new as Message
                        // Filtering
                        if (projectId) {
                            if (newMessage.project_id !== projectId) return
                        } else {
                            if (newMessage.project_id) return
                        }

                        // Remove user from typing list if they sent a message
                        setTypingUsers(prev => {
                            const next = new Map(prev)
                            next.delete(newMessage.sender_id)
                            return next
                        })

                        if (newMessage.sender_id === currentUserRef.current.id) {
                            setMessages(prev => {
                                // Find optimistic message
                                const optimisticMatch = prev.find(m =>
                                    m.is_sender &&
                                    m.message === newMessage.message &&
                                    Math.abs(new Date(m.created_at).getTime() - new Date(newMessage.created_at).getTime()) < 10000
                                )

                                if (optimisticMatch) {
                                    return prev.map(m => m === optimisticMatch ? { ...newMessage, is_sender: true, sender: currentUserRef.current, message_reads: [] } : m)
                                }
                                return [...prev, { ...newMessage, is_sender: true, sender: currentUserRef.current, message_reads: [] }]
                            })
                        } else {
                            // Someone else
                            const { data: senderData } = await supabase
                                .from('users')
                                .select('name, avatar, email')
                                .eq('id', newMessage.sender_id)
                                .single()

                            // Mark as read immediately if visible
                            // In a real app we might check visibility/focus
                            markProjectMessagesAsRead(teamId, projectId || null)

                            setMessages(prev => [...prev, {
                                ...newMessage,
                                sender: senderData || undefined,
                                is_sender: false,
                                message_reads: []
                            }])
                        }
                    } else if (payload.eventType === 'DELETE') {
                        setMessages(prev => prev.filter(m => m.id !== payload.old.id))
                    }
                }
            )
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'message_reads'
                },
                (payload) => {
                    const newRead = payload.new
                    setMessages(prev => prev.map(msg => {
                        if (msg.id === newRead.message_id) {
                            // Add to reads
                            const existingReads = (msg.message_reads || []) as any[]
                            if (existingReads.some(r => r.user_id === newRead.user_id)) return msg

                            const updatedReads = [...existingReads, { user_id: newRead.user_id }]

                            // Check for double tick condition
                            // Read by everyone excluding sender
                            // If I am sender, I need (totalMembers - 1) reads.
                            const isReadByAll = updatedReads.length >= (totalMembersRef.current - 1)

                            return {
                                ...msg,
                                message_reads: updatedReads,
                                read_status: isReadByAll ? 'read' : 'delivered' // Upgrade to delivered at least if someone read it
                            }
                        }
                        return msg
                    }))
                }
            )
            .on(
                'broadcast',
                { event: 'typing' },
                (payload) => {
                    const { userId, name } = payload.payload
                    if (userId === currentUserRef.current.id) return

                    setTypingUsers(prev => {
                        const next = new Map(prev)
                        next.set(userId, { name, until: Date.now() + 3000 })
                        return next
                    })
                }
            )
            .subscribe((status) => {
                if (status === 'SUBSCRIBED') setStatus('connected')
                if (status === 'CLOSED' || status === 'CHANNEL_ERROR') setStatus('disconnected')
            })

        return () => {
            supabase.removeChannel(channel)
        }
    }, [teamId, projectId, supabase])

    // Optimistic Delete Handler
    const handleDeleteMessage = useCallback((messageId: string) => {
        setMessages(prev => prev.filter(m => m.id !== messageId))
    }, [])

    return (
        <div className="flex flex-col h-full bg-background/50 backdrop-blur-2xl relative overflow-hidden ring-1 ring-border/50">
            <ConnectionStatus status={status} />

            <MessageList
                messages={messages}
                teamId={teamId}
                projectId={projectId}
                onDelete={handleDeleteMessage}
                members={members}
            />

            <div className="absolute bottom-20 left-0 right-0 z-10 pointer-events-none">
                <TypingIndicator users={Array.from(typingUsers.entries()).map(([id, data]) => ({ id, name: data.name }))} />
            </div>

            <ChatInput
                teamId={teamId}
                projectId={projectId}
                members={members}
                onSendMessage={handleSendMessage}
                onTyping={handleBroadcastTyping}
            />
        </div>
    )
}

'use client'

import { useState, useRef, KeyboardEvent } from 'react'
import { Send, Smile, Paperclip, CheckSquare, X, Calendar as CalendarIcon } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { sendMessage, createTaskDirectly } from '@/app/dashboard/chat/actions'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { toast } from 'sonner'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { cn } from '@/lib/utils'
import { AttachmentPicker } from './AttachmentPicker'
import EmojiPicker, { EmojiClickData, Theme } from 'emoji-picker-react'
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover'
import { Calendar } from '@/components/ui/calendar'
import { format } from 'date-fns'

interface ChatInputProps {
    teamId: string
    projectId?: string
    members?: any[]
    onSendMessage?: (formData: FormData) => Promise<void>
    onTyping?: () => void
}

export function ChatInput({ teamId, projectId, members = [], onSendMessage, onTyping }: ChatInputProps) {
    const [message, setMessage] = useState('')
    const [isSending, setIsSending] = useState(false)
    const textareaRef = useRef<HTMLTextAreaElement>(null)

    // Task Mode State
    const [isTaskMode, setIsTaskMode] = useState(false)
    const [assignedTo, setAssignedTo] = useState<string>('')
    const [priority, setPriority] = useState<string>('Medium')
    const [dueDate, setDueDate] = useState<Date>()

    // Mention State
    const [mentionQuery, setMentionQuery] = useState<string | null>(null)
    const [mentionIndex, setMentionIndex] = useState<number>(-1)
    const [mentionedUserIds, setMentionedUserIds] = useState<Set<string>>(new Set())
    const [activeMemberIndex, setActiveMemberIndex] = useState(0)


    const handleSend = async () => {
        if ((!message.trim() && attachments.length === 0) || isSending) return

        setIsSending(true)
        try {
            if (isTaskMode) {
                // Create Task
                const formData = new FormData()
                formData.append('title', message)
                formData.append('teamId', teamId)
                if (projectId) formData.append('projectId', projectId)
                if (assignedTo) formData.append('assignedTo', assignedTo)
                if (dueDate) formData.append('dueDate', dueDate.toISOString())
                formData.append('priority', priority)

                await createTaskDirectly(formData)
                toast.success('Task created successfully')
                setIsTaskMode(false)
                setAssignedTo('')
                setPriority('Medium')
                setDueDate(undefined)
            } else {
                // Send Message
                const formData = new FormData()
                formData.append('message', message)
                formData.append('teamId', teamId)
                if (projectId) formData.append('projectId', projectId)

                const meta: any = {}
                if (attachments.length > 0) meta.attachments = attachments
                if (mentionedUserIds.size > 0) meta.mentions = Array.from(mentionedUserIds)

                if (Object.keys(meta).length > 0) {
                    formData.append('metadata', JSON.stringify(meta))
                }

                if (onSendMessage) {
                    await onSendMessage(formData)
                } else {
                    await sendMessage(formData)
                }
            }

            setMessage('')
            setAttachments([])
            setMentionedUserIds(new Set())

            // Reset height
            if (textareaRef.current) {
                textareaRef.current.style.height = 'auto'
            }
        } catch (error) {
            console.error('Failed to send:', error)
            toast.error(isTaskMode ? 'Failed to create task' : 'Failed to send message')
        } finally {
            setIsSending(false)
            // Focus back
            textareaRef.current?.focus()
        }
    }

    const handleKeyDown = (e: KeyboardEvent<HTMLTextAreaElement>) => {
        if (mentionQuery !== null) {
            if (e.key === 'ArrowDown') {
                e.preventDefault()
                setActiveMemberIndex(prev => (prev + 1) % filteredMembers.length)
                return
            }
            if (e.key === 'ArrowUp') {
                e.preventDefault()
                setActiveMemberIndex(prev => (prev - 1 + filteredMembers.length) % filteredMembers.length)
                return
            }
            if (e.key === 'Enter' || e.key === 'Tab') {
                e.preventDefault()
                if (filteredMembers[activeMemberIndex]) {
                    selectMember(filteredMembers[activeMemberIndex])
                }
                return
            }
            if (e.key === 'Escape') {
                setMentionQuery(null)
                return
            }
        }

        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault()
            handleSend()
        }
    }

    const lastTypingTimeRef = useRef(0)

    // Auto-resize textarea
    const handleInput = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        const val = e.target.value
        setMessage(val)
        e.target.style.height = 'auto'
        e.target.style.height = `${Math.min(e.target.scrollHeight, 150)}px`

        // Mention Detection
        const selectionStart = e.target.selectionStart
        const textBeforeCursor = val.slice(0, selectionStart)
        const lastAt = textBeforeCursor.lastIndexOf('@')

        if (lastAt !== -1) {
            const query = textBeforeCursor.slice(lastAt + 1)
            // Ensure no spaces (simple mention) - or allow spaces if we want "@John Doe"
            // Let's stick to simple first: standard is usually name without spaces OR spaces allowed if we check bounds.
            // Usually we stop at space if we support complex like Slack, but simplistic is fine.
            // Actually, names have spaces. So we should allow spaces IF it looks like a name start.
            // But typically we simply check if there's a newline or specific chars breaking it.
            // Let's simplify: Only trigger if there is no space so far OR allow spaces.
            // Standard: Check if we are "in" a mention.
            // If query contains newline, abort.
            if (!query.includes('\n')) {
                setMentionQuery(query)
                setMentionIndex(lastAt)
                setActiveMemberIndex(0)
            } else {
                setMentionQuery(null)
            }
        } else {
            setMentionQuery(null)
        }


        // Throttle typing event
        const now = Date.now()
        if (onTyping && now - lastTypingTimeRef.current > 2000) {
            onTyping()
            lastTypingTimeRef.current = now
        }
    }

    const filteredMembers = mentionQuery !== null
        ? members.filter(m => m.name.toLowerCase().includes(mentionQuery.toLowerCase()))
        : []

    const selectMember = (member: any) => {
        const before = message.slice(0, mentionIndex)
        const after = message.slice(mentionIndex + (mentionQuery?.length || 0) + 1)
        const newText = `${before}@${member.name} ${after}`
        setMessage(newText)
        setMentionedUserIds(prev => new Set(prev).add(member.id))
        setMentionQuery(null)
        // Focus and set cursor? Hard with React controlled input sometimes.
        // We let user continue typing at end of name.
    }

    const [attachments, setAttachments] = useState<{ type: string, item: any }[]>([])

    const addAttachment = (type: string, item: any) => {
        // Prevent duplicates
        if (attachments.some(a => a.item.id === item.id && a.type === type)) return
        setAttachments([...attachments, { type, item }])
    }

    const removeAttachment = (index: number) => {
        setAttachments(attachments.filter((_, i) => i !== index))
    }

    const onEmojiClick = (emojiData: EmojiClickData) => {
        setMessage(prev => prev + emojiData.emoji)
    }

    return (
        <div className="p-4 border-t border-border bg-card/10 backdrop-blur-sm relative">
            {/* Mention Popup */}
            {mentionQuery !== null && filteredMembers.length > 0 && (
                <div className="absolute bottom-full left-4 mb-2 w-64 bg-popover border rounded-lg shadow-lg overflow-hidden z-50 animate-in slide-in-from-bottom-2">
                    <div className="p-1">
                        {filteredMembers.map((member, i) => (
                            <button
                                key={member.id}
                                className={cn(
                                    "w-full flex items-center gap-2 px-2 py-1.5 text-sm rounded-sm transition-colors",
                                    i === activeMemberIndex ? "bg-accent text-accent-foreground" : "hover:bg-muted"
                                )}
                                onClick={() => selectMember(member)}
                            >
                                <Avatar className="h-6 w-6">
                                    <AvatarImage src={member.avatar} />
                                    <AvatarFallback>{member.name?.[0]}</AvatarFallback>
                                </Avatar>
                                <span>{member.name}</span>
                            </button>
                        ))}
                    </div>
                </div>
            )}

            {attachments.length > 0 && (
                <div className="flex flex-wrap gap-2 mb-2">
                    {attachments.map((att, i) => (
                        <div key={i} className="flex items-center gap-2 p-2 bg-muted/50 rounded-lg max-w-fit animate-in slide-in-from-bottom-2 fade-in relative group">
                            <div className="text-xs font-medium flex items-center gap-1.5">
                                <span className="capitalize text-muted-foreground">{att.type.replace('_', ' ')}:</span>
                                <span className="text-foreground">{att.item.title || att.item.name}</span>
                            </div>
                            <Button
                                variant="ghost"
                                size="icon"
                                className="h-4 w-4 rounded-full ml-1 opacity-0 group-hover:opacity-100 transition-opacity"
                                onClick={() => removeAttachment(i)}
                            >
                                <X className="h-3 w-3" />
                            </Button>
                        </div>
                    ))}
                </div>
            )}

            {isTaskMode && (
                <div className="flex items-center gap-2 mb-2 animate-in slide-in-from-bottom-2 fade-in">
                    <div className="bg-primary/10 text-primary px-2 py-1 rounded text-xs font-semibold flex items-center gap-1">
                        <CheckSquare className="h-3 w-3" />
                        New Task
                    </div>
                    <Select value={assignedTo} onValueChange={setAssignedTo}>
                        <SelectTrigger className="h-7 w-[150px] text-xs">
                            <SelectValue placeholder="Assign to" />
                        </SelectTrigger>
                        <SelectContent>
                            {members.map(member => (
                                <SelectItem key={member.id} value={member.id}>
                                    <div className="flex items-center gap-2">
                                        <Avatar className="h-4 w-4">
                                            <AvatarImage src={member.avatar} />
                                            <AvatarFallback>{member.name?.[0]}</AvatarFallback>
                                        </Avatar>
                                        {member.name}
                                    </div>
                                </SelectItem>
                            ))}
                        </SelectContent>
                    </Select>

                    <Select value={priority} onValueChange={setPriority}>
                        <SelectTrigger className="h-7 w-[100px] text-xs">
                            <SelectValue placeholder="Priority" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="Low">Low</SelectItem>
                            <SelectItem value="Medium">Medium</SelectItem>
                            <SelectItem value="High">High</SelectItem>
                        </SelectContent>
                    </Select>

                    <Popover>
                        <PopoverTrigger asChild>
                            <Button
                                variant="outline"
                                size="sm"
                                className={cn(
                                    "h-7 border-dashed gap-1 text-xs font-normal",
                                    !dueDate && "text-muted-foreground"
                                )}
                            >
                                <CalendarIcon className="h-3 w-3" />
                                {dueDate ? format(dueDate, "MMM d") : "Due"}
                            </Button>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0" align="start">
                            <Calendar
                                mode="single"
                                selected={dueDate}
                                onSelect={setDueDate}
                                initialFocus
                            />
                        </PopoverContent>
                    </Popover>

                    <Button
                        variant="ghost"
                        size="icon"
                        className="h-6 w-6 ml-auto hover:bg-destructive/10 hover:text-destructive"
                        onClick={() => setIsTaskMode(false)}
                    >
                        <X className="h-3 w-3" />
                    </Button>
                </div>
            )}

            <div className={`relative flex items-end gap-2 bg-card border rounded-xl p-2 shadow-sm focus-within:ring-2 focus-within:ring-primary/20 transition-all ${isTaskMode ? 'border-primary/50 ring-1 ring-primary/20' : 'border-border'}`}>
                <div className="flex flex-col gap-1 items-center pb-1">
                    <Button
                        variant={isTaskMode ? "default" : "ghost"}
                        size="icon"
                        className={`h-9 w-9 shrink-0 rounded-full ${isTaskMode ? '' : 'text-muted-foreground hover:text-foreground'}`}
                        onClick={() => setIsTaskMode(!isTaskMode)}
                        title="Create Task"
                    >
                        <CheckSquare className="h-5 w-5" />
                    </Button>
                    {!isTaskMode && (
                        <AttachmentPicker projectId={projectId} onSelect={addAttachment} />
                    )}
                </div>

                <Textarea
                    ref={textareaRef}
                    value={message}
                    onChange={handleInput}
                    onKeyDown={handleKeyDown}
                    placeholder={isTaskMode ? "What needs to be done?" : attachments.length > 0 ? "Add a message..." : "Type a message..."}
                    className="min-h-[2.5rem] max-h-[150px] w-full resize-none border-0 bg-transparent p-2 focus-visible:ring-0 shadow-none px-0 py-1.5"
                    rows={1}
                />

                <div className="flex items-center gap-1 shrink-0 pb-1">
                    {!isTaskMode && (
                        <Popover>
                            <PopoverTrigger asChild>
                                <Button variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-foreground rounded-full">
                                    <Smile className="h-5 w-5" />
                                </Button>
                            </PopoverTrigger>
                            <PopoverContent side="top" align="end" className="w-full p-0 border-none bg-transparent shadow-none">
                                <EmojiPicker
                                    onEmojiClick={onEmojiClick}
                                    theme={Theme.AUTO}
                                    width={350}
                                    height={400}
                                />
                            </PopoverContent>
                        </Popover>
                    )}
                    <Button
                        onClick={handleSend}
                        disabled={(!message.trim() && attachments.length === 0) || isSending}
                        size="icon"
                        className="h-8 w-8 rounded-full"
                    >
                        {isTaskMode ? <CheckSquare className="h-4 w-4" /> : <Send className="h-4 w-4" />}
                    </Button>
                </div>
            </div>
        </div >
    )
}

'use client'

import Link from 'next/link'
import { useParams, usePathname } from 'next/navigation'
import { cn } from '@/lib/utils'
import { Hash, Users, Folder, Plus } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/components/ui/collapsible'
import { useState } from 'react'
import { CreateTeamDialog } from './CreateTeamDialog'
import { CreateProjectDialog } from './CreateProjectDialog'
import { TeamActionsMenu } from './TeamActionsMenu'
import { Badge } from '@/components/ui/badge'
import { getUnreadCounts } from '@/app/dashboard/chat/actions'
import { useEffect } from 'react'


export type Project = {
    id: string
    name: string
    team_id: string
}

export type Team = {
    id: string
    name: string
    currentUserRole?: string
    projects: Project[]
}

interface ChatSidebarProps {
    teams: Team[]
    onSelect?: () => void
}

export function ChatSidebar({ teams, onSelect }: ChatSidebarProps) {
    const params = useParams()
    const pathname = usePathname()
    const currentTeamId = params.teamId as string

    // State for collapsible teams, default all open for now
    const [openTeams, setOpenTeams] = useState<Record<string, boolean>>(
        teams.reduce((acc, team) => ({ ...acc, [team.id]: true }), {})
    )

    const toggleTeam = (teamId: string) => {
        setOpenTeams(prev => ({ ...prev, [teamId]: !prev[teamId] }))
    }

    const [unreadCounts, setUnreadCounts] = useState<Record<string, number>>({})

    useEffect(() => {
        const fetchUnread = async () => {
            try {
                const counts = await getUnreadCounts()
                setUnreadCounts(counts)
            } catch (e) {
                console.error("Failed to load unread counts", e)
            }
        }

        // Initial fetch
        fetchUnread()

        // Poll every 10 seconds? Or just once. 
        // Realtime would be better but polling is safer for quick MVP.
        const interval = setInterval(fetchUnread, 15000)
        return () => clearInterval(interval)
    }, [])

    return (
        <div className="flex flex-col h-full border-r border-border bg-card/30 backdrop-blur-md">
            <div className="p-4 border-b border-border flex items-center justify-between">
                <h2 className="font-semibold text-lg">Teams</h2>
                <CreateTeamDialog />
            </div>

            <ScrollArea className="flex-1 p-2">
                <div className="space-y-4">
                    {teams.length === 0 && (
                        <div className="text-sm text-muted-foreground p-2">
                            No teams yet. Create one to start chatting!
                        </div>
                    )}

                    {teams.map((team) => (
                        <Collapsible
                            key={team.id}
                            open={openTeams[team.id]}
                            onOpenChange={() => toggleTeam(team.id)}
                        >
                            <div className="flex items-center group">
                                <Link
                                    href={`/dashboard/chat/${team.id}`}
                                    onClick={onSelect}
                                    className={cn(
                                        "flex-1 flex items-center gap-2 px-2 py-1.5 text-sm font-medium rounded-md hover:bg-accent hover:text-accent-foreground transition-colors",
                                        currentTeamId === team.id && !pathname.includes('/project/') ? "bg-accent text-accent-foreground" : "text-muted-foreground"
                                    )}
                                >
                                    <div className="relative">
                                        <Users className="h-4 w-4" />
                                        {unreadCounts[team.id] > 0 && (
                                            <span className="absolute -top-1.5 -right-1.5 flex h-3 w-3 items-center justify-center rounded-full bg-destructive text-[9px] font-bold text-destructive-foreground">
                                                {unreadCounts[team.id]}
                                            </span>
                                        )}
                                    </div>
                                    <span className="flex-1 truncate">{team.name}</span>
                                    {unreadCounts[team.id] > 0 && (
                                        <Badge variant="secondary" className="h-5 px-1.5 text-[10px] bg-primary/10 text-primary hover:bg-primary/20">
                                            {unreadCounts[team.id]} new
                                        </Badge>
                                    )}
                                </Link>
                                <TeamActionsMenu
                                    teamId={team.id}
                                    teamName={team.name}
                                    currentUserRole={team.currentUserRole}
                                />
                                <CollapsibleTrigger asChild>
                                    <Button variant="ghost" size="sm" className="h-6 w-6 p-0 ml-1 opacity-0 group-hover:opacity-100 transition-opacity rotate-90 data-[state=open]:rotate-0">
                                        <Hash className="h-3 w-3" />
                                    </Button>
                                </CollapsibleTrigger>
                            </div>

                            <CollapsibleContent className="pl-4 pt-1 space-y-1">
                                {team.projects?.map((project) => (
                                    <Link
                                        key={project.id}
                                        href={`/dashboard/chat/${team.id}/project/${project.id}`}
                                        onClick={onSelect}
                                        className={cn(
                                            "flex items-center gap-2 px-2 py-1.5 text-sm rounded-md hover:bg-accent hover:text-accent-foreground transition-colors w-full",
                                            pathname.includes(project.id) ? "bg-accent/50 text-accent-foreground" : "text-muted-foreground"
                                        )}
                                    >
                                        <div className="relative">
                                            <Folder className="h-3 w-3" />
                                            {unreadCounts[project.id] > 0 && (
                                                <span className="absolute -top-1 -right-1 flex h-2.5 w-2.5 items-center justify-center rounded-full bg-destructive text-[8px] font-bold text-destructive-foreground">
                                                </span>
                                            )}
                                        </div>
                                        <span className="flex-1 truncate">{project.name}</span>
                                        {unreadCounts[project.id] > 0 && (
                                            <span className="text-[10px] text-muted-foreground flex items-center justify-center bg-muted h-4 min-w-[16px] px-1 rounded-full">
                                                {unreadCounts[project.id]}
                                            </span>
                                        )}
                                    </Link>
                                ))}
                                {['owner', 'admin', 'member'].includes(team.currentUserRole || '') && (
                                    <CreateProjectDialog teamId={team.id} />
                                )}
                            </CollapsibleContent>
                        </Collapsible>
                    ))}
                </div>
            </ScrollArea>
        </div>
    )
}

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { createProject, getTeamMembers } from '@/app/dashboard/teams/actions'
import { Plus, Loader2 } from 'lucide-react'
import { Checkbox } from '@/components/ui/checkbox'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'

interface CreateProjectDialogProps {
    teamId: string
}

export function CreateProjectDialog({ teamId }: CreateProjectDialogProps) {
    const [open, setOpen] = useState(false)
    const [name, setName] = useState('')
    const [isLoading, setIsLoading] = useState(false)
    const router = useRouter()

    useEffect(() => {
        if (!open) {
            // Reset
            setName('')
        }
    }, [open])

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!name.trim()) return

        setIsLoading(true)
        try {
            const formData = new FormData()
            formData.append('name', name)
            formData.append('teamId', teamId)
            // Empty members list implies private/just me, or we could change backend to auto-add all.
            // Requirement is "remove selecting members", assuming they want to skip the step.
            formData.append('members', JSON.stringify([]))

            await createProject(formData)
            setOpen(false)
            router.refresh()
        } catch (error) {
            console.error('Failed to create project:', error)
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                <Button variant="ghost" size="sm" className="w-full justify-start pl-2 text-xs text-muted-foreground h-7 hover:text-foreground">
                    <Plus className="h-3 w-3 mr-2" />
                    Add Project
                </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-[425px]">
                <DialogHeader>
                    <DialogTitle>Create Project</DialogTitle>
                    <DialogDescription>
                        Create a private space for your project context.
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit}>
                    <div className="grid gap-4 py-4">
                        <div className="grid gap-2">
                            <Label htmlFor="name">
                                Project Name
                            </Label>
                            <Input
                                id="name"
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                placeholder="e.g. Marketing Campaign"
                                disabled={isLoading}
                                autoFocus
                            />
                        </div>
                    </div>
                    <DialogFooter>
                        <Button type="submit" disabled={isLoading || !name.trim()}>
                            {isLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                            Create Project
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState } from 'react'
import { format } from 'date-fns'
import { MoreHorizontal, SquareCheckBig, Check, CheckCheck, Smile } from 'lucide-react'
import { cn } from '@/lib/utils'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { Button } from '@/components/ui/button'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { createTaskFromMessage, deleteMessage } from '@/app/dashboard/chat/actions'
import { toast } from 'sonner'
import { SharedContentCard } from './SharedContentCard'
import { CreateTaskDialog } from './CreateTaskDialog'

export interface Message {
    id: string
    team_id: string
    project_id: string | null
    sender_id: string
    message: string
    created_at: string
    sender?: {
        name: string
        avatar: string
        email: string
    }
    is_sender?: boolean
    read_status?: 'sent' | 'delivered' | 'read'
    metadata?: any
    message_reads?: { user_id: string }[]
}

interface MessageItemProps {
    message: Message
    isConsecutive?: boolean
    teamId: string
    projectId?: string
    onDelete?: (id: string) => void
    members?: any[]
}

// Helper to render mentions
const renderMessageWithMentions = (text: string, mentions: string[] | undefined, isSender: boolean) => {
    if (!text) return null
    if (!mentions || mentions.length === 0) return text

    // Split by spaces or special chars to find potential mentions
    // Simpler: Regex for @Word
    const parts = text.split(/(@\w+(?:\s+\w+)?)/g) // Split keeping delimiters

    return parts.map((part, i) => {
        if (part.startsWith('@')) {
            return (
                <span
                    key={i}
                    className={cn(
                        "font-bold px-1 rounded-sm",
                        isSender
                            ? "bg-primary-foreground/20 text-primary-foreground"
                            : "bg-primary/10 text-primary"
                    )}
                >
                    {part}
                </span>
            )
        }
        return part
    })
}

export function MessageItem({ message, isConsecutive, teamId, projectId, onDelete, members = [] }: MessageItemProps) {
    const isSender = message.is_sender
    const [isCreateTaskOpen, setIsCreateTaskOpen] = useState(false)

    // Format time
    const time = format(new Date(message.created_at), 'p')

    const handleCreateTask = () => {
        setIsCreateTaskOpen(true)
    }

    const handleDelete = async () => {
        try {
            // Optimistic update
            onDelete?.(message.id)
            await deleteMessage(message.id, teamId)
            toast.success("Message deleted")
        } catch (e) {
            console.error("Failed to delete message", e)
            toast.error("Failed to delete message")
        }
    }

    return (
        <div className={cn("flex w-full group mb-1", isSender ? "justify-end" : "justify-start")}>
            <div className={cn("flex max-w-[70%] gap-2", isSender ? "flex-row-reverse" : "flex-row")}>
                {/* Avatar - only show if not consecutive and not sender (or if we want sender avatar too) */}
                {!isSender && !isConsecutive && (
                    <Avatar className="h-8 w-8 mt-1">
                        <AvatarImage src={message.sender?.avatar || ''} />
                        <AvatarFallback>{message.sender?.name?.[0] || '?'}</AvatarFallback>
                    </Avatar>
                )}
                {!isSender && isConsecutive && <div className="w-8" />}

                <div className={cn("flex flex-col", isSender ? "items-end" : "items-start")}>
                    {/* Sender Name - only if not consecutive and not me */}
                    {!isSender && !isConsecutive && (
                        <span className="text-xs text-muted-foreground ml-1 mb-1">
                            {message.sender?.name}
                        </span>
                    )}

                    <div className="relative group/msg">
                        <div
                            className={cn(
                                "px-4 py-2 rounded-2xl text-sm shadow-sm relative transition-all duration-300 group-hover/msg:shadow-md",
                                isSender
                                    ? "bg-primary text-primary-foreground rounded-tr-sm border border-white/10 hover:scale-[1.01] shadow-indigo-500/10"
                                    : "bg-card backdrop-blur-xl border border-border/50 text-card-foreground rounded-tl-sm hover:scale-[1.01]"
                            )}
                        >
                            {renderMessageWithMentions(message.message, message.metadata?.mentions, isSender || false)}
                        </div>

                        {/* Actions Overlay */}
                        <div className={cn(
                            "absolute top-0 opacity-0 group-hover/msg:opacity-100 transition-opacity flex items-center gap-1",
                            isSender ? "-left-14" : "-right-14"
                        )}>
                            {/* Add Task Quick Action */}
                            <Button
                                variant="ghost"
                                size="icon"
                                className="h-6 w-6 rounded-full bg-background border border-border shadow-sm"
                                title="Create Task"
                                onClick={handleCreateTask}
                            >
                                <SquareCheckBig className="h-3 w-3" />
                            </Button>

                            <DropdownMenu>
                                <DropdownMenuTrigger asChild>
                                    <Button variant="ghost" size="icon" className="h-6 w-6 rounded-full bg-background border border-border shadow-sm">
                                        <MoreHorizontal className="h-3 w-3" />
                                    </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent align={isSender ? 'end' : 'start'}>
                                    <DropdownMenuItem onClick={handleCreateTask}>
                                        <SquareCheckBig className="mr-2 h-4 w-4" />
                                        Create Task
                                    </DropdownMenuItem>
                                    <DropdownMenuSeparator />
                                    {isSender && (
                                        <DropdownMenuItem className="text-destructive" onClick={handleDelete}>
                                            Delete Message
                                        </DropdownMenuItem>
                                    )}
                                </DropdownMenuContent>
                            </DropdownMenu>
                        </div>
                    </div>

                    {/* Shared Content Card */}
                    {message.metadata && (
                        <div className="mt-2 mb-1 flex flex-wrap gap-2">
                            {/* New Array Format */}
                            {(message.metadata as any).attachments?.map((att: any, i: number) => (
                                <SharedContentCard key={i} attachment={att} />
                            ))}

                            {/* Legacy Single Format */}
                            {!(message.metadata as any).attachments && (message.metadata as any).attachment && (
                                <SharedContentCard attachment={(message.metadata as any).attachment} />
                            )}
                        </div>
                    )}

                    {/* Metadata (Time + Read Receipt) */}
                    <div className="flex items-center gap-1 mt-1 px-1">
                        <span className="text-[10px] text-muted-foreground">
                            {time}
                        </span>
                        {isSender && (
                            <span className="text-muted-foreground">
                                {message.read_status === 'read' ? (
                                    <CheckCheck className="h-3 w-3 text-blue-500" />
                                ) : message.read_status === 'delivered' ? (
                                    <CheckCheck className="h-3 w-3" />
                                ) : (
                                    <Check className="h-3 w-3" />
                                )}
                            </span>
                        )}
                    </div>
                </div>

            </div>
            <CreateTaskDialog
                open={isCreateTaskOpen}
                onOpenChange={setIsCreateTaskOpen}
                messageId={message.id}
                initialTitle={message.message.substring(0, 50) + (message.message.length > 50 ? '...' : '')}
                teamId={teamId}
                projectId={projectId}
                members={members}
            />
        </div >
    )
}

'use client'

import { useEffect, useRef } from 'react'
import { MessageItem, Message } from './MessageItem'

import { differenceInMinutes, isSameDay, isToday, isYesterday, format } from 'date-fns'

function formatDateLabel(date: Date) {
    if (isToday(date)) return 'Today'
    if (isYesterday(date)) return 'Yesterday'
    return format(date, 'MMMM d, yyyy')
}

import { motion, AnimatePresence } from 'framer-motion'

// Simplified MessageList
export function MessageList({ messages, teamId, projectId, onDelete, members }: {
    messages: Message[],
    teamId: string,
    projectId?: string,
    onDelete?: (id: string) => void,
    members: any[]
}) {
    const scrollRef = useRef<HTMLDivElement>(null)

    // Scroll to bottom when messages change
    useEffect(() => {
        if (scrollRef.current) {
            // Use requestAnimationFrame to ensure DOM is ready
            requestAnimationFrame(() => {
                if (scrollRef.current) {
                    scrollRef.current.scrollTop = scrollRef.current.scrollHeight
                }
            })
        }
    }, [messages.length])

    // Group messages
    const groupedMessages = messages.map((msg, index) => {
        const prevMsg = messages[index - 1]
        const isConsecutive = prevMsg
            && prevMsg.sender_id === msg.sender_id
            && differenceInMinutes(new Date(msg.created_at), new Date(prevMsg.created_at)) < 5

        return { ...msg, isConsecutive }
    })

    return (
        <div
            ref={scrollRef}
            className="flex-1 min-h-0 w-full overflow-y-auto p-4 scrollbar-thin scrollbar-thumb-muted scrollbar-track-transparent overscroll-y-contain"
            style={{ WebkitOverflowScrolling: 'touch' }}
        >
            <div className="flex flex-col gap-1 pb-4">
                <AnimatePresence initial={false}>
                    {groupedMessages.length === 0 && (
                        <motion.div
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 0.5, y: 0 }}
                            exit={{ opacity: 0 }}
                            className="flex flex-col items-center justify-center py-20 text-muted-foreground"
                        >
                            <p>No messages yet.</p>
                            <p className="text-sm">Start the conversation!</p>
                        </motion.div>
                    )}

                    {groupedMessages.map((msg, index) => {
                        const prevMsg = groupedMessages[index - 1];
                        const isNewDay = !prevMsg || !isSameDay(new Date(msg.created_at), new Date(prevMsg.created_at));

                        return (
                            <motion.div
                                key={msg.id + '-container'}
                                layout
                                initial={{ opacity: 0, y: 20, scale: 0.95 }}
                                animate={{ opacity: 1, y: 0, scale: 1 }}
                                transition={{
                                    type: "spring",
                                    stiffness: 260,
                                    damping: 20,
                                    delay: Math.min(index * 0.05, 0.5) // Stagger for initial load
                                }}
                                className="flex flex-col"
                            >
                                {isNewDay && (
                                    <div className="flex items-center justify-center my-4">
                                        <div className="bg-muted/30 backdrop-blur-md text-[10px] uppercase tracking-widest text-muted-foreground px-4 py-1 rounded-full border border-border/50">
                                            {formatDateLabel(new Date(msg.created_at))}
                                        </div>
                                    </div>
                                )}
                                <MessageItem
                                    message={msg}
                                    isConsecutive={msg.isConsecutive}
                                    teamId={teamId}
                                    projectId={projectId}
                                    onDelete={onDelete}
                                    members={members}
                                />
                            </motion.div>
                        );
                    })}
                </AnimatePresence>
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { updateProject, deleteProject } from '@/app/dashboard/chat/actions'
import { addTeamMember, getTeamMembers, updateMemberRole, removeTeamMember } from '@/app/dashboard/teams/actions'
import { Settings, Trash2, UserPlus, Loader2 } from 'lucide-react'
import { useRouter } from 'next/navigation'
import { Separator } from '@/components/ui/separator'
import { useEffect } from 'react'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { ScrollArea } from "@/components/ui/scroll-area"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"

import { DeleteProjectDialog } from './DeleteProjectDialog'

interface ProjectSettingsDialogProps {
    teamId: string
    projectId: string
    currentName: string
    currentUserRole?: string
}

interface Member {
    id: string
    name: string
    email: string
    avatar: string
    role: string
    isCreator?: boolean
}

export function ProjectSettingsDialog({ teamId, projectId, currentName, currentUserRole = 'member' }: ProjectSettingsDialogProps) {
    const [name, setName] = useState(currentName)
    const [open, setOpen] = useState(false)
    const [isLoading, setIsLoading] = useState(false)

    // Delete Dialog State
    const [showDeleteDialog, setShowDeleteDialog] = useState(false)

    const canEdit = ['owner', 'admin'].includes(currentUserRole)

    // Add Member State
    const [inviteEmail, setInviteEmail] = useState('')
    const [isInviting, setIsInviting] = useState(false)
    const [inviteMessage, setInviteMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null)

    // Members List State
    const [members, setMembers] = useState<Member[]>([])
    const [isLoadingMembers, setIsLoadingMembers] = useState(false)

    const router = useRouter()

    const fetchMembers = async () => {
        setIsLoadingMembers(true)
        try {
            const data = await getTeamMembers(teamId)
            // @ts-ignore
            setMembers(data)
        } catch (error) {
            console.error(error)
        } finally {
            setIsLoadingMembers(false)
        }
    }

    const handleOpenChange = (isOpen: boolean) => {
        setOpen(isOpen)
        if (isOpen) {
            setName(currentName)
            setInviteMessage(null)
            setInviteEmail('')
            fetchMembers()
        }
    }

    const handleRoleChange = async (userId: string, newRole: string) => {
        try {
            await updateMemberRole(teamId, userId, newRole)
            setMembers(prev => prev.map(m => m.id === userId ? { ...m, role: newRole } : m))
        } catch (error) {
            console.error('Failed to update role:', error)
        }
    }

    const handleRemoveMember = async (userId: string) => {
        if (!confirm('Are you sure you want to remove this member?')) return
        try {
            await removeTeamMember(teamId, userId)
            setMembers(prev => prev.filter(m => m.id !== userId))
        } catch (error) {
            console.error('Failed to remove member:', error)
        }
    }

    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!name.trim()) return

        setIsLoading(true)
        try {
            const formData = new FormData()
            formData.append('name', name)
            formData.append('projectId', projectId)
            formData.append('teamId', teamId)
            await updateProject(formData)
            setOpen(false)
        } catch (error) {
            console.error('Failed to update project:', error)
        } finally {
            setIsLoading(false)
        }
    }

    const handleInvite = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!inviteEmail.trim()) return

        setIsInviting(true)
        setInviteMessage(null)

        try {
            const formData = new FormData()
            formData.append('email', inviteEmail)
            formData.append('teamId', teamId)
            const result = await addTeamMember(formData)

            if (result.success) {
                setInviteMessage({ type: 'success', text: result.message || 'Member added to team successfully!' })
                setInviteEmail('')
            } else {
                setInviteMessage({ type: 'error', text: result.error || 'Failed to add member.' })
            }
        } catch (error) {
            console.error('Failed to add member:', error)
            setInviteMessage({
                type: 'error',
                text: 'An unexpected error occurred.'
            })
        } finally {
            setIsInviting(false)
        }
    }

    return (
        <>
            <Dialog open={open} onOpenChange={handleOpenChange}>
                <DialogTrigger asChild>
                    <Button variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-foreground">
                        <Settings className="h-4 w-4" />
                    </Button>
                </DialogTrigger>
                <DialogContent className="sm:max-w-[425px]">
                    <DialogHeader>
                        <DialogTitle>Project Settings</DialogTitle>
                        <DialogDescription>
                            Manage your project settings and members.
                        </DialogDescription>
                    </DialogHeader>

                    <div className="space-y-6 py-4">
                        {/* Edit Name Section */}
                        <div className="space-y-2">
                            <Label htmlFor="name">Project Name</Label>
                            <div className="flex gap-2">
                                <Input
                                    id="name"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    disabled={isLoading || !canEdit}
                                />
                                {canEdit && (
                                    <Button onClick={handleUpdate} disabled={isLoading || !name.trim()}>
                                        Save
                                    </Button>
                                )}
                            </div>
                        </div>

                        <Separator />

                        {/* Add Member Section */}
                        {canEdit && (
                            <>
                                <div className="space-y-2">
                                    <Label htmlFor="email">Add Member</Label>
                                    <DialogDescription className="text-xs">
                                        Invite users to the team to give them access to this project.
                                    </DialogDescription>
                                    <div className="flex gap-2">
                                        <Input
                                            id="email"
                                            type="email"
                                            placeholder="user@example.com"
                                            value={inviteEmail}
                                            onChange={(e) => setInviteEmail(e.target.value)}
                                            disabled={isInviting}
                                        />
                                        <Button onClick={handleInvite} disabled={isInviting || !inviteEmail.trim()} variant="secondary">
                                            <UserPlus className="h-4 w-4 mr-2" />
                                            Add
                                        </Button>
                                    </div>
                                    {inviteMessage && (
                                        <p className={`text-sm ${inviteMessage.type === 'success' ? 'text-green-500' : 'text-destructive'}`}>
                                            {inviteMessage.text}
                                        </p>
                                    )}
                                </div>
                                <Separator />
                            </>
                        )}

                        {/* Members List Section */}
                        <div className="space-y-2">
                            <Label>Project Members</Label>
                            <DialogDescription className="text-xs">
                                People with access to this project (via team membership).
                            </DialogDescription>

                            <div className="border rounded-md h-[150px] overflow-hidden bg-background/50">
                                {isLoadingMembers ? (
                                    <div className="flex justify-center items-center h-full">
                                        <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                                    </div>
                                ) : (
                                    <ScrollArea className="h-full">
                                        <div className="p-2 space-y-2">
                                            {members.map((member) => (
                                                <div key={member.id} className="flex items-center justify-between gap-3 p-2 hover:bg-accent/50 rounded-sm">
                                                    <div className="flex items-center gap-3 overflow-hidden">
                                                        <Avatar className="h-8 w-8">
                                                            <AvatarImage src={member.avatar || ''} />
                                                            <AvatarFallback>{member.name?.[0] || '?'}</AvatarFallback>
                                                        </Avatar>
                                                        <div className="min-w-0">
                                                            <p className="text-sm font-medium truncate">{member.name}</p>
                                                            <p className="text-xs text-muted-foreground truncate">{member.email}</p>
                                                        </div>
                                                    </div>

                                                    <div className="flex items-center gap-2">
                                                        {canEdit ? (
                                                            <>
                                                                <Select
                                                                    value={member.role}
                                                                    onValueChange={(val) => handleRoleChange(member.id, val)}
                                                                    disabled={member.isCreator}
                                                                >
                                                                    <SelectTrigger className="w-[90px] h-7 text-xs">
                                                                        <SelectValue />
                                                                    </SelectTrigger>
                                                                    <SelectContent>
                                                                        <SelectItem value="owner">Owner</SelectItem>
                                                                        <SelectItem value="admin">Admin</SelectItem>
                                                                        <SelectItem value="member">Member</SelectItem>
                                                                    </SelectContent>
                                                                </Select>

                                                                <Button
                                                                    variant="ghost"
                                                                    size="icon"
                                                                    className="h-7 w-7 text-muted-foreground hover:text-destructive"
                                                                    onClick={() => handleRemoveMember(member.id)}
                                                                    disabled={member.isCreator}
                                                                >
                                                                    <Trash2 className="h-4 w-4" />
                                                                </Button>
                                                            </>
                                                        ) : (
                                                            <span className="text-xs text-muted-foreground capitalize">{member.role}</span>
                                                        )}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </ScrollArea>
                                )}
                            </div>
                        </div>

                        {/* Delete Section */}
                        {canEdit && (
                            <>
                                <Separator />
                                <div className="space-y-2">
                                    <Label className="text-destructive">Danger Zone</Label>
                                    <Button
                                        variant="destructive"
                                        className="w-full"
                                        onClick={() => setShowDeleteDialog(true)}
                                    >
                                        <Trash2 className="mr-2 h-4 w-4" />
                                        Delete Project
                                    </Button>
                                </div>
                            </>
                        )}
                    </div>
                </DialogContent>
            </Dialog>

            <DeleteProjectDialog
                teamId={teamId}
                projectId={projectId}
                projectName={currentName}
                open={showDeleteDialog}
                onOpenChange={setShowDeleteDialog}
            />
        </>
    )
}

'use client'

import { Book, FileText, TrendingUp, GraduationCap, ArrowRight, Check } from 'lucide-react'
import Link from 'next/link'
import { copyItemToAccount } from '@/app/dashboard/chat/shared-actions'
import { toast } from 'sonner'
import { useRouter } from 'next/navigation'
import { useState } from 'react'

export function SharedContentCard({ attachment }: { attachment: { type: string, item: any } }) {
    const { type, item } = attachment
    const router = useRouter()
    const [isLoading, setIsLoading] = useState(false)

    let icon = <FileText className="h-4 w-4" />
    let color = "bg-blue-500/10 text-blue-500"

    switch (type) {
        case 'resource':
            icon = <Book className="h-4 w-4" />
            color = "bg-purple-500/10 text-purple-500"
            break
        case 'note':
            icon = <FileText className="h-4 w-4" />
            color = "bg-yellow-500/10 text-yellow-500"
            break
        case 'learning_path':
            icon = <GraduationCap className="h-4 w-4" />
            color = "bg-green-500/10 text-green-500"
            break
        case 'finance':
            icon = <TrendingUp className="h-4 w-4" />
            color = "bg-emerald-500/10 text-emerald-500"
            break
        case 'roadmap':
            icon = <TrendingUp className="h-4 w-4" /> // Or a Map-like icon
            color = "bg-indigo-500/10 text-indigo-500"
            break
    }

    const handleClick = async (e: React.MouseEvent) => {
        e.preventDefault()
        e.stopPropagation()

        // Direct navigation for Roadmap (Page handles logic)
        if (type === 'roadmap') {
            router.push(`/dashboard/roadmaps/${item.id}`)
            return
        }

        if (type === 'finance') {
            router.push('/dashboard/finances')
            return
        }

        setIsLoading(true)
        const toastId = toast.loading('Opening shared item...')

        try {
            const result = await copyItemToAccount(item.id, type)

            if (result.success && result.newId) {
                if (result.isNew) {
                    toast.success('Added to account!', { id: toastId })
                } else if ((result as any).updated) {
                    toast.success('Updated local copy!', { id: toastId })
                } else {
                    toast.success('Opening item...', { id: toastId })
                }

                // Redirect to the item page
                if (type === 'resource') {
                    router.push('/dashboard/resources')
                } else if (type === 'note') {
                    router.push(`/dashboard/notes`)
                } else if (type === 'learning_path') {
                    router.push(`/dashboard/paths/${result.newId}/edit`)
                }
            }
        } catch (error: any) {
            console.error('Failed to open shared item:', error)
            // Handle specific duplicate error if it somehow slips through (though we now handle updates)
            if (error.message?.includes('already added')) {
                toast.error('Item already exists', { id: toastId })
            } else {
                toast.error('Failed to open item', { id: toastId })
            }
        } finally {
            setIsLoading(false)
        }
    }

    return (
        <div
            onClick={handleClick}
            className="flex items-center gap-3 p-3 rounded-xl border border-border bg-card/50 hover:bg-muted/50 transition-colors w-64 group/card cursor-pointer"
        >
            <div className={`p-2 rounded-lg ${color}`}>
                {icon}
            </div>
            <div className="flex-1 min-w-0">
                <div className="text-xs font-medium text-muted-foreground capitalize mb-0.5">{type.replace('_', ' ')}</div>
                <div className="text-sm font-medium truncate">{item.title || item.name}</div>
            </div>
            {isLoading ? (
                <div className="h-4 w-4 rounded-full border-2 border-primary border-t-transparent animate-spin" />
            ) : (
                <ArrowRight className="h-4 w-4 text-muted-foreground opacity-0 group-hover/card:opacity-100 transition-opacity" />
            )}
        </div>
    )
}

