export function SharedItemsList({ items: initialItems, teamId }: SharedItemsListProps) {
    const [items, setItems] = useState(initialItems)
    const [addingIds, setAddingIds] = useState<Set<string>>(new Set())

    const handleAdd = async (itemId: string) => {
        setAddingIds(prev => new Set(prev).add(itemId))
        try {
            await addToMyAccount(itemId)
            toast.success('Added to your account')
            setItems(prev => prev.map(item => item.id === itemId ? { ...item, is_added: true } : item))
        } catch (error: any) {
            toast.error(error.message || 'Failed to add item')
        } finally {
            setAddingIds(prev => {
                const next = new Set(prev)
                next.delete(itemId)
                return next
            })
        }
    }

    const renderCard = (item: SharedItem) => {
        const Icon = item.shared_type === 'resource' ? FileText :
            item.shared_type === 'learning_path' ? BookOpen :
                item.shared_type === 'roadmap' ? MapIcon : StickyNote

        return (
            <Card key={item.id} className="overflow-hidden">
                <CardHeader className="p-4 bg-muted/30 pb-2">
                    <div className="flex justify-between items-start gap-2">
                        <div className="flex items-center gap-2">
                            <div className="h-8 w-8 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                                <Icon className="h-4 w-4 text-primary" />
                            </div>
                            <div>
                                <CardTitle className="text-base line-clamp-1">{item.details.title}</CardTitle>
                                <CardDescription className="text-xs">
                                    Shared by {item.shared_by_user.name} ΓÇó {new Date(item.created_at).toLocaleDateString()}
                                </CardDescription>
                            </div>
                        </div>
                        <Badge variant="outline" className="capitalize text-[10px] h-5 px-1.5">
                            {item.shared_type.replace('_', ' ')}
                        </Badge>
                    </div>
                </CardHeader>
                <CardContent className="p-4 pt-2 text-sm text-muted-foreground">
                    <p className="line-clamp-2">
                        {item.details.summary || item.details.description || (item.details.content ? item.details.content.slice(0, 100) : 'No description')}
                    </p>
                    {item.details.url && (
                        <a href={item.details.url} target="_blank" rel="noreferrer" className="flex items-center gap-1 text-primary hover:underline mt-2 text-xs">
                            <ExternalLink className="h-3 w-3" />
                            {item.details.url}
                        </a>
                    )}
                </CardContent>
                <CardFooter className="p-4 pt-0 flex gap-2">
                    {/* View Button - For now just a placeholder or could open a modal */}
                    <Button variant="outline" size="sm" className="flex-1 h-8 text-xs" onClick={() => handleView(item)}>
                        {/* TODO: Add proper view link/modal */}
                        <span className={item.shared_type === 'roadmap' ? '' : 'cursor-not-allowed opacity-50'}>
                            {item.shared_type === 'roadmap' ? 'Open' : 'Preview'}
                        </span>
                    </Button>

                    <Button
                        size="sm"
                        className="flex-1 h-8 text-xs"
                        onClick={() => handleAdd(item.id)}
                        disabled={item.is_added || addingIds.has(item.id)}
                        variant={item.is_added ? "secondary" : "default"}
                    >
                        {item.is_added ? (
                            <>
                                <Check className="h-3 w-3 mr-1" />
                                Added
                            </>
                        ) : (
                            <>
                                <ArrowDownToLine className="h-3 w-3 mr-1" />
                                {addingIds.has(item.id) ? 'Adding...' : 'Add to My Account'}
                            </>
                        )}
                    </Button>
                </CardFooter>
            </Card>
        )
    }

    const handleView = (item: SharedItem) => {
        if (item.shared_type === 'roadmap') {
            window.location.href = `/dashboard/roadmaps/${item.id}`
        }
    }

    const filterItems = (type: string) => {
        if (type === 'all') return items
        return items.filter(item => item.shared_type === type)
    }

    return (
        <Tabs defaultValue="all" className="w-full h-full flex flex-col">
            <div className="px-6 border-b border-border flex items-center justify-between bg-card">
                <TabsList className="h-12 bg-transparent p-0 gap-4">
                    <TabsTrigger value="all" className="data-[state=active]:bg-primary/10 h-8 rounded-full px-4 text-xs">All</TabsTrigger>
                    <TabsTrigger value="resource" className="data-[state=active]:bg-primary/10 h-8 rounded-full px-4 text-xs">Resources</TabsTrigger>
                    <TabsTrigger value="learning_path" className="data-[state=active]:bg-primary/10 h-8 rounded-full px-4 text-xs">Learning Paths</TabsTrigger>
                    <TabsTrigger value="note" className="data-[state=active]:bg-primary/10 h-8 rounded-full px-4 text-xs">Notes</TabsTrigger>
                    <TabsTrigger value="roadmap" className="data-[state=active]:bg-primary/10 h-8 rounded-full px-4 text-xs">Roadmaps</TabsTrigger>
                </TabsList>
            </div>

            <TabsContent value="all" className="flex-1 p-0 m-0 overflow-hidden">
                <ScrollArea className="h-full p-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 pb-20">
                        {filterItems('all').map(renderCard)}
                        {filterItems('all').length === 0 && (
                            <div className="col-span-full text-center py-20 text-muted-foreground">
                                No shared items found.
                            </div>
                        )}
                    </div>
                </ScrollArea>
            </TabsContent>

            {['resource', 'learning_path', 'note', 'roadmap'].map(type => (
                <TabsContent key={type} value={type} className="flex-1 p-0 m-0 overflow-hidden">
                    <ScrollArea className="h-full p-6">
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 pb-20">
                            {filterItems(type).map(renderCard)}
                            {filterItems(type).length === 0 && (
                                <div className="col-span-full text-center py-20 text-muted-foreground">
                                    No {type.replace('_', ' ')}s found.
                                </div>
                            )}
                        </div>
                    </ScrollArea>
                </TabsContent>
            ))}
        </Tabs>
    )
}

'use client'

import { useState, useEffect } from 'react'
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { ScrollArea } from "@/components/ui/scroll-area"
import { updateTeam, getTeamMembers, updateMemberRole, removeTeamMember } from '@/app/dashboard/teams/actions'
import { Loader2, Trash2 } from 'lucide-react'

interface TeamSettingsDialogProps {
    teamId: string
    currentName: string
    open: boolean
    onOpenChange: (open: boolean) => void
    currentUserRole?: string
}

interface Member {
    id: string
    name: string
    email: string
    avatar: string
    role: string
    isCreator?: boolean
}

export function TeamSettingsDialog({ teamId, currentName, open, onOpenChange, currentUserRole = 'member' }: TeamSettingsDialogProps) {
    const [name, setName] = useState(currentName)
    const [isLoading, setIsLoading] = useState(false)
    const [members, setMembers] = useState<Member[]>([])
    const [isLoadingMembers, setIsLoadingMembers] = useState(false)

    const canEdit = ['owner', 'admin'].includes(currentUserRole)

    useEffect(() => {
        if (open) {
            fetchMembers()
        }
    }, [open, teamId])

    const fetchMembers = async () => {
        setIsLoadingMembers(true)
        try {
            const data = await getTeamMembers(teamId)
            // @ts-ignore
            setMembers(data)
        } catch (error) {
            console.error(error)
        } finally {
            setIsLoadingMembers(false)
        }
    }

    const handleUpdateName = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!name.trim()) return

        setIsLoading(true)
        try {
            const formData = new FormData()
            formData.append('name', name)
            formData.append('teamId', teamId)
            await updateTeam(formData)
            // Optional: show success
        } catch (error) {
            console.error('Failed to update team:', error)
        } finally {
            setIsLoading(false)
        }
    }

    const handleRoleChange = async (userId: string, newRole: string) => {
        try {
            await updateMemberRole(teamId, userId, newRole)
            setMembers(prev => prev.map(m => m.id === userId ? { ...m, role: newRole } : m))
        } catch (error) {
            console.error('Failed to update role:', error)
        }
    }

    const handleRemoveMember = async (userId: string) => {
        if (!confirm('Are you sure you want to remove this member?')) return
        try {
            await removeTeamMember(teamId, userId)
            setMembers(prev => prev.filter(m => m.id !== userId))
        } catch (error) {
            console.error('Failed to remove member:', error)
        }
    }

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[550px] h-[500px] flex flex-col">
                <DialogHeader>
                    <DialogTitle>Team Settings</DialogTitle>
                    <DialogDescription>
                        Manage your team profile and members.
                    </DialogDescription>
                </DialogHeader>

                <Tabs defaultValue="general" className="flex-1 flex flex-col overflow-hidden">
                    <TabsList className="grid w-full grid-cols-2">
                        <TabsTrigger value="general">General</TabsTrigger>
                        <TabsTrigger value="members">Members</TabsTrigger>
                    </TabsList>

                    <TabsContent value="general" className="py-4">
                        <form onSubmit={handleUpdateName} className="space-y-4">
                            <div className="grid grid-cols-4 items-center gap-4">
                                <Label htmlFor="name" className="text-right">
                                    Team Name
                                </Label>
                                <Input
                                    id="name"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    className="col-span-3"
                                    disabled={isLoading || !canEdit}
                                />
                            </div>
                            {canEdit && (
                                <div className="flex justify-end">
                                    <Button type="submit" disabled={isLoading || !name.trim()}>
                                        {isLoading ? 'Saving...' : 'Save Changes'}
                                    </Button>
                                </div>
                            )}
                        </form>
                    </TabsContent>

                    <TabsContent value="members" className="flex-1 flex flex-col overflow-hidden mt-4">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="text-sm font-medium">Team Members ({members.length})</h3>
                        </div>

                        {isLoadingMembers ? (
                            <div className="flex justify-center p-4">
                                <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                            </div>
                        ) : (
                            <ScrollArea className="flex-1 pr-4">
                                <div className="space-y-4">
                                    {members.map((member) => (
                                        <div key={member.id} className="flex items-center justify-between gap-4 border-b border-border/50 pb-3 last:border-0 last:pb-0">
                                            <div className="flex items-center gap-3 overflow-hidden">
                                                <Avatar>
                                                    <AvatarImage src={member.avatar || ''} />
                                                    <AvatarFallback>{member.name?.[0] || '?'}</AvatarFallback>
                                                </Avatar>
                                                <div className="min-w-0">
                                                    <p className="text-sm font-medium truncate">{member.name}</p>
                                                    <p className="text-xs text-muted-foreground truncate">{member.email}</p>
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-2">
                                                {canEdit ? (
                                                    <>
                                                        <Select
                                                            value={member.role}
                                                            onValueChange={(val) => handleRoleChange(member.id, val)}
                                                            disabled={member.isCreator}
                                                        >
                                                            <SelectTrigger className="w-[100px] h-8">
                                                                <SelectValue />
                                                            </SelectTrigger>
                                                            <SelectContent>
                                                                <SelectItem value="owner">Owner</SelectItem>
                                                                <SelectItem value="admin">Admin</SelectItem>
                                                                <SelectItem value="member">Member</SelectItem>
                                                            </SelectContent>
                                                        </Select>

                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            className="h-8 w-8 text-muted-foreground hover:text-destructive"
                                                            disabled={member.isCreator}
                                                            onClick={() => handleRemoveMember(member.id)}
                                                        >
                                                            <Trash2 className="h-4 w-4" />
                                                        </Button>
                                                    </>
                                                ) : (
                                                    <span className="text-xs text-muted-foreground capitalize">{member.role}</span>
                                                )}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </ScrollArea>
                        )}
                    </TabsContent>
                </Tabs>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { usePathname } from 'next/navigation'
import { cn } from '@/lib/utils'

interface DashboardContentProps {
    children: React.ReactNode
    deviceType?: string | null
    isTeamOnly?: boolean
}

import { AnimatePresence, motion } from 'framer-motion'
import { GridBreakingOverlay } from './ui/grid-breaking-overlay'
import { useRouter } from 'next/navigation'
import { useEffect } from 'react'

export function DashboardContent({ children, deviceType, isTeamOnly }: DashboardContentProps) {
    const pathname = usePathname()
    const router = useRouter()
    const isChat = pathname?.startsWith('/dashboard/chat')

    useEffect(() => {
        if (isTeamOnly) {
            const allowedPaths = ['/dashboard/teams', '/dashboard/chat', '/dashboard/settings']
            // Check if current path starts with any allowed path.
            // Also allow /dashboard/teams/* etc.
            const isAllowed = allowedPaths.some(path => pathname?.startsWith(path))

            if (!isAllowed && pathname !== '/dashboard/teams') {
                router.replace('/dashboard/teams')
            }
        }
    }, [isTeamOnly, pathname, router])

    const transitionProps = {
        initial: { opacity: 0, y: 10, scale: 0.99 },
        animate: { opacity: 1, y: 0, scale: 1 },
        exit: { opacity: 0, y: -10, scale: 0.99 },
        transition: { duration: 0.4, ease: [0.23, 1, 0.32, 1] as any }
    }

    if (isChat) {
        return (
            <div className="flex-1 flex flex-col min-h-0 overflow-hidden relative">
                <GridBreakingOverlay />
                <div className="md:hidden px-4 py-2 text-xs text-muted-foreground shrink-0 select-none">
                    Detected Device: {deviceType}
                </div>
                <div className="hidden md:block mb-0 text-xs text-muted-foreground shrink-0 px-4 pt-2 select-none">
                    Detected Device: {deviceType}
                </div>
                <AnimatePresence mode="wait">
                    <motion.div
                        key={pathname}
                        {...transitionProps}
                        className="flex-1 flex flex-col min-h-0"
                    >
                        {children}
                    </motion.div>
                </AnimatePresence>
            </div>
        )
    }

    return (
        <div className="flex-1 min-h-0 relative">
            <GridBreakingOverlay />
            <main className="p-4 md:p-8 relative z-10 w-full max-w-[1600px] mx-auto">
                <div className="mb-4 text-xs text-muted-foreground md:hidden select-none">
                    Detected Device: {deviceType}
                </div>
                <div className="hidden md:block mb-4 text-xs text-muted-foreground select-none">
                    Detected Device: {deviceType}
                </div>
                <AnimatePresence mode="wait">
                    <motion.div
                        key={pathname}
                        {...transitionProps}
                    >
                        {children}
                    </motion.div>
                </AnimatePresence>
            </main>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { format } from 'date-fns'

export function DateTimeDisplay() {
    const [mounted, setMounted] = useState(false)
    const [date, setDate] = useState(new Date())

    useEffect(() => {
        setMounted(true)
        const timer = setInterval(() => {
            setDate(new Date())
        }, 1000)

        return () => clearInterval(timer)
    }, [])

    if (!mounted) {
        return <div className="h-6 w-48 bg-muted animate-pulse rounded" /> // Loading skeleton
    }

    return (
        <div className="flex flex-col items-end">
            <p className="text-xl font-bold tracking-tight">
                {format(date, 'h:mm:ss a')}
            </p>
            <p className="text-sm text-muted-foreground font-medium">
                {format(date, 'EEEE, MMMM d, yyyy')}
            </p>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { Plus, Loader2 } from 'lucide-react'
import { toast } from 'sonner'
import { Button } from '@/components/ui/button'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select'
import { addTransaction } from '@/app/dashboard/finances/actions'
import { useSearchParams, useRouter } from 'next/navigation'

interface Category {
    id: string
    name: string
    type: 'Income' | 'Expense'
    user_id: string
}

interface Project {
    id: string
    name: string
}

const DEFAULT_CATEGORIES = {
    Income: ['Salary', 'Freelance', 'Investment', 'Other'],
    Expense: ['Food', 'Rent', 'Transport', 'Utilities', 'Entertainment', 'Shopping', 'Health', 'Other']
}

export function AddTransactionDialog({ categories, projects, onAdd }: { categories: Category[], projects?: Project[], onAdd?: (t: any) => void }) {
    const searchParams = useSearchParams()
    const router = useRouter()
    const [open, setOpen] = useState(false)
    const [type, setType] = useState<'Income' | 'Expense'>('Expense')
    const [category, setCategory] = useState<string>('')
    const [loading, setLoading] = useState(false)

    // Auto-open dialog if ?add=true is in URL
    useEffect(() => {
        if (searchParams.get('add') === 'true') {
            setOpen(true)
            const params = new URLSearchParams(searchParams.toString())
            params.delete('add')
            router.replace(`?${params.toString()}`, { scroll: false })
        }
    }, [searchParams, router])

    // Merge default categories with custom categories from DB
    const availableCategories = [
        ...DEFAULT_CATEGORIES[type],
        ...categories
            .filter(c => c.type === type && !DEFAULT_CATEGORIES[type].includes(c.name))
            .map(c => c.name)
    ].sort()

    // Ensure 'Other' is always at the end
    const sortedCategories = availableCategories.filter(c => c !== 'Other').concat('Other')
    // Remove duplicates just in case
    const uniqueCategories = Array.from(new Set(sortedCategories))

    async function onSubmit(formData: FormData) {
        setLoading(true)

        // Optimistic Update
        if (onAdd) {
            const type = formData.get('type') as 'Income' | 'Expense'
            const amount = parseFloat(formData.get('amount') as string)
            const dateStr = formData.get('date') as string
            const projectId = formData.get('projectId') as string
            const description = formData.get('description') as string
            const categoryName = formData.get('category') as string
            const customCategory = formData.get('custom_category') as string

            let finalCategoryName = categoryName
            if (categoryName === 'Other' && customCategory && customCategory.trim()) {
                finalCategoryName = customCategory.trim()
            }

            const newTransaction = {
                id: crypto.randomUUID(),
                type,
                amount,
                date: dateStr ? new Date(dateStr).toISOString() : new Date().toISOString(),
                category_id: 'temp',
                category_name: finalCategoryName,
                description,
                user_id: 'temp',
                project_id: projectId !== 'undefined' ? projectId : undefined
            }
            onAdd(newTransaction)
            setOpen(false)
        }

        try {
            const result = await addTransaction(formData)
            if (result?.error) {
                toast.error(result.error)
                // In a perfect world we would revert optimistic here
                return
            }
            if (!onAdd) {
                toast.success("Transaction added successfully")
                setOpen(false)
            } else {
                toast.success("Transaction added successfully")
            }
        } catch (error) {
            console.error('Failed to add transaction', error)
            toast.error("An unexpected error occurred")
        } finally {
            setLoading(false)
        }
    }

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                <Button>
                    <Plus className="mr-2 h-4 w-4" />
                    Add Transaction
                </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-[425px]">
                <DialogHeader>
                    <DialogTitle>Add Transaction</DialogTitle>
                </DialogHeader>
                <form action={onSubmit} className="grid gap-4 py-4">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="grid gap-2">
                            <Label htmlFor="type">Type</Label>
                            <Select name="type" value={type} onValueChange={(v: 'Income' | 'Expense') => setType(v)}>
                                <SelectTrigger>
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="Income">Income</SelectItem>
                                    <SelectItem value="Expense">Expense</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="grid gap-2">
                            <Label htmlFor="date">Date</Label>
                            <Input type="date" name="date" required defaultValue={new Date().toISOString().split('T')[0]} />
                        </div>
                    </div>

                    <div className="grid gap-2">
                        <Label htmlFor="project">Project (Optional)</Label>
                        <Select name="projectId">
                            <SelectTrigger>
                                <SelectValue placeholder="Select Project" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="undefined">None</SelectItem>
                                {projects?.map(p => (
                                    <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="grid gap-2">
                        <Label htmlFor="amount">Amount</Label>
                        <Input type="number" name="amount" placeholder="0.00" required step="0.01" />
                    </div>

                    <div className="grid gap-2">
                        <Label htmlFor="category">Category</Label>
                        <Select name="category" required onValueChange={setCategory}>
                            <SelectTrigger>
                                <SelectValue placeholder="Select Category" />
                            </SelectTrigger>
                            <SelectContent>
                                {uniqueCategories.map(cat => (
                                    <SelectItem key={cat} value={cat}>{cat}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    {category === 'Other' && (
                        <div className="grid gap-2">
                            <Label htmlFor="custom_category">Custom Name (Optional)</Label>
                            <Input
                                name="custom_category"
                                placeholder="e.g. Side Hustle, Gift"
                                className="bg-muted/50"
                            />
                        </div>
                    )}

                    <div className="grid gap-2">
                        <Label htmlFor="description">Description</Label>
                        <Input name="description" placeholder="Optional note" />
                    </div>

                    <div className="flex justify-end">
                        <Button type="submit" disabled={loading}>
                            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Save
                        </Button>
                    </div>
                </form>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts'
import { formatCurrency } from '@/lib/utils'

interface ChartData {
    name: string
    value: number
    [key: string]: any
}

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#a855f7', '#ec4899', '#6366f1']

export function BreakdownChart({ data }: { data: ChartData[] }) {
    const total = data.reduce((acc, item) => acc + item.value, 0)

    return (
        <div className="flex flex-col md:flex-row items-center justify-center gap-8 h-full">
            <div className="h-[250px] w-[250px] relative">
                <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie
                            data={data}
                            cx="50%"
                            cy="50%"
                            innerRadius={60}
                            outerRadius={80}
                            paddingAngle={2}
                            dataKey="value"
                        >
                            {data.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                            ))}
                        </Pie>
                        <Tooltip
                            formatter={(value: any) => formatCurrency(Number(value || 0))}
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                        />
                    </PieChart>
                </ResponsiveContainer>
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                    <div className="text-center">
                        <p className="text-xs text-muted-foreground">Total</p>
                        <p className="text-lg font-bold">{formatCurrency(total)}</p>
                    </div>
                </div>
            </div>

            <div className="flex-1 w-full md:max-w-xs space-y-3">
                {data.map((item, index) => {
                    const percentage = total > 0 ? ((item.value / total) * 100).toFixed(1) : '0'
                    return (
                        <div key={item.name} className="flex items-center justify-between text-sm">
                            <div className="flex items-center gap-2">
                                <div
                                    className="w-3 h-3 rounded-full"
                                    style={{ backgroundColor: COLORS[index % COLORS.length] }}
                                />
                                <span className="font-medium">{item.name}</span>
                            </div>
                            <div className="flex items-center gap-4 text-muted-foreground">
                                <span>{percentage}%</span>
                                <span className="w-20 text-right font-mono">{formatCurrency(item.value)}</span>
                            </div>
                        </div>
                    )
                })}
            </div>
        </div>
    )
}

'use client'

import { useOptimistic, useTransition } from 'react'
import { AddTransactionDialog } from './add-transaction-dialog'
import { TransactionList } from './transaction-list'
import { FinanceOverview } from './finance-overview'

interface Transaction {
    id: string
    type: string
    amount: number
    category_id: string
    category_name: string
    description?: string
    date: string
    user_id: string
    project_id?: string
    created_at?: string
}

interface Category {
    id: string
    name: string
    type: 'Income' | 'Expense'
    user_id: string
}

interface Project {
    id: string
    name: string
}

interface FinancesManagerProps {
    initialTransactions: Transaction[]
    categories: Category[]
    projects: Project[]
}

export function FinancesManager({ initialTransactions, categories, projects }: FinancesManagerProps) {
    const [isPending, startTransition] = useTransition()
    const [optimisticTransactions, addOptimisticTransaction] = useOptimistic(
        initialTransactions,
        (state, newTransaction: Transaction) => [newTransaction, ...state].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    )

    return (
        <div className="space-y-6">
