                <AddTransactionDialog
                    categories={categories}
                    projects={projects}
                    onAdd={(newTransaction) => {
                        startTransition(() => {
                            addOptimisticTransaction(newTransaction)
                        })
                    }}
                />
            </div>

            <FinanceOverview transactions={optimisticTransactions} />

            <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-7">
                <div className="col-span-1 md:col-span-2 lg:col-span-7">
                    <TransactionList
                        transactions={optimisticTransactions}
                        categories={categories}
                        projects={projects}
                    />
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { Plus, Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select'
import { createHabit } from '@/app/dashboard/habits/actions'
import { useSearchParams, useRouter } from 'next/navigation'

export function CreateHabitDialog({ onAdd }: { onAdd?: (habit: any) => void }) {
    const searchParams = useSearchParams()
    const router = useRouter()
    const [open, setOpen] = useState(false)
    const [loading, setLoading] = useState(false)

    // Auto-open dialog if ?add=true is in URL
    useEffect(() => {
        if (searchParams.get('add') === 'true') {
            setOpen(true)
            const params = new URLSearchParams(searchParams.toString())
            params.delete('add')
            router.replace(`?${params.toString()}`, { scroll: false })
        }
    }, [searchParams, router])

    async function onSubmit(formData: FormData) {
        setLoading(true)

        // Optimistic Update
        if (onAdd) {
            const name = formData.get('name') as string
            const frequency = formData.get('frequency') as string

            const tempHabit = {
                id: crypto.randomUUID(),
                name,
                frequency,
                created_at: new Date().toISOString(),
                habit_logs: []
            }
            onAdd(tempHabit)
            setOpen(false) // Close dialog immediately
        }

        try {
            await createHabit(formData)
            if (!onAdd) setOpen(false) // Fallback close if no optimistic handler
        } catch (error) {
            console.error(error)
            // Ideally revert optimistic update here, but for now we rely on revalidation
        } finally {
            setLoading(false)
        }
    }

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                <Button>
                    <Plus className="mr-2 h-4 w-4" />
                    New Habit
                </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-[425px]">
                <DialogHeader>
                    <DialogTitle>Create Habit</DialogTitle>
                </DialogHeader>
                <form action={onSubmit} className="grid gap-4 py-4">
                    <div className="grid gap-2">
                        <Label htmlFor="name">Name</Label>
                        <Input id="name" name="name" placeholder="e.g. Read 30 mins" required />
                    </div>
                    <div className="grid gap-2">
                        <Label htmlFor="frequency">Frequency</Label>
                        <Select name="frequency" defaultValue="Daily">
                            <SelectTrigger>
                                <SelectValue placeholder="Select frequency" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="Daily">Daily</SelectItem>
                                <SelectItem value="Weekly">Weekly</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                    <div className="flex justify-end">
                        <Button type="submit" disabled={loading}>
                            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Save Habit
                        </Button>
                    </div>
                </form>
            </DialogContent>
        </Dialog>
    )
}

'use client'

import { useState, useOptimistic, startTransition } from 'react'
import { format } from 'date-fns'
import { Check, Trash2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { deleteHabit, toggleHabit } from '@/app/dashboard/habits/actions'
import { EditHabitDialog } from '@/components/habits/edit-habit-dialog'
import { ConfirmDeleteDialog } from '@/components/confirm-delete-dialog'
import { HoverEffect } from '@/components/ui/hover-effect'
import { SpotlightCard } from '@/components/ui/spotlight-card'
import { cn } from '@/lib/utils'

interface Habit {
    id: string
    name: string
    frequency: string
    created_at: string
    habit_logs: {
        date: string
        status: boolean
    }[]
}

export function HabitItem({ habit }: { habit: Habit }) {
    const now = new Date()
    // Ensure consistent date formatting
    const today = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`

    const initialCompleted = habit.habit_logs.find(log => log.date === today)?.status || false

    // Optimistic state
    // We only need to optimize the 'isCompleted' status for immediate feedback
    const [optimisticCompleted, addOptimisticCompleted] = useOptimistic(
        initialCompleted,
        (state, newStatus: boolean) => newStatus
    )

    const [isPending, setIsPending] = useState(false)

    async function handleToggle() {
        const newStatus = !optimisticCompleted

        // Immediate visual update
        startTransition(() => {
            addOptimisticCompleted(newStatus)
        })

        setIsPending(true)
        try {
            await toggleHabit(habit.id, today, newStatus)
        } catch (error) {
            console.error('Failed to toggle habit', error)
            // Revert optimistic update is handled automatically if we rely on props, 
            // but useOptimistic persists until next prop update. 
            // If server fails, we might be desynced until revalidation.
            // For now, assume success or error toast (todo).
        } finally {
            setIsPending(false)
        }
    }

    const completionCount = habit.habit_logs.filter(l => l.status).length

    return (
        <HoverEffect variant="lift" className="h-full">
            <SpotlightCard className="h-full transition-colors hover:border-primary/50">
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">
                        {habit.name}
                    </CardTitle>
                    <div className="flex items-center gap-1">
                        <EditHabitDialog habit={habit} />
                        <ConfirmDeleteDialog
                            trigger={
                                <Button variant="ghost" size="icon" className="h-6 w-6 text-muted-foreground hover:text-destructive">
                                    <Trash2 className="h-4 w-4" />
                                </Button>
                            }
                            onConfirm={() => deleteHabit(habit.id)}
                            title="Delete Habit"
                            description="Are you sure you want to delete this habit? All progress will be lost."
                        />
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="flex items-center justify-between">
                        <div className="text-2xl font-bold">{completionCount} Days</div>
                        <Button
                            size="icon"
                            variant={optimisticCompleted ? "default" : "outline"}
                            className={cn(
                                "h-10 w-10 transition-all",
                                optimisticCompleted && "bg-green-500 hover:bg-green-600 border-green-500",
                                isPending && "opacity-70"
                            )}
                            onClick={handleToggle}
                            disabled={isPending}
                        >
                            <Check className={cn("h-6 w-6", optimisticCompleted ? "text-white" : "text-muted-foreground")} />
                        </Button>
                    </div>
                    <div className="flex justify-between items-center mt-1">
                        <p className="text-xs text-muted-foreground">
                            {habit.frequency}
                        </p>
                        <p className="text-xs text-muted-foreground">
                            Started: {format(new Date(habit.created_at), 'MMM d, yyyy')}
                        </p>
                    </div>
                </CardContent>
            </SpotlightCard>
        </HoverEffect>
    )
}

