'use client'

import { useState, useTransition } from 'react'
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { MoreVertical, ExternalLink, Map, BookOpen, FolderInput, Pencil, Trash2, CheckCircle, CheckCircle2 } from 'lucide-react'
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu'
import { deleteLearningPath, toggleLearningPathCompletion } from '@/app/dashboard/actions'
import Link from 'next/link'
import { ConfirmDeleteDialog } from '@/components/confirm-delete-dialog'
import { MoveToCollectionDialog } from '@/components/move-to-collection-dialog'
import { cn } from '@/lib/utils'
import { format } from 'date-fns'
import { HoverEffect } from '@/components/ui/hover-effect'
import { SpotlightCard } from '@/components/ui/spotlight-card'

export interface LearningPathProps {
    id: string
    title: string
    description?: string
    links?: string[]
    created_at: string
    is_completed?: boolean
}

export function LearningPathCard({ path }: { path: LearningPathProps }) {
    const [isPending, startTransition] = useTransition()
    const [isDeleteOpen, setIsDeleteOpen] = useState(false)
    const [isMoveOpen, setIsMoveOpen] = useState(false)

    const handleDelete = () => {
        startTransition(async () => {
            await deleteLearningPath(path.id)
            setIsDeleteOpen(false)
        })
    }

    const handleToggleCompletion = () => {
        startTransition(async () => {
            await toggleLearningPathCompletion(path.id, !path.is_completed)
        })
    }

    return (
        <>
            <HoverEffect variant="lift" className="h-full w-full">
                <SpotlightCard className={cn("flex flex-col h-full hover:shadow-md transition-shadow", isPending && "opacity-50", path.is_completed && "border-green-500/50 bg-green-50/10 dark:bg-green-900/10")}>
                    <CardHeader className="p-4 pb-2">
                        <div className="flex justify-between items-start gap-2">
                            <div className="flex flex-wrap gap-2 items-center text-sm font-medium text-muted-foreground w-full min-w-0">
                                <div className="flex items-center gap-2">
                                    <Map className="h-4 w-4 flex-shrink-0" />
                                    <span>Learning Path</span>
                                </div>
                                {path.is_completed && <span className="text-green-600 dark:text-green-400 text-xs flex items-center gap-1 whitespace-nowrap"><CheckCircle2 className="h-3 w-3" /> Completed</span>}
                            </div>
                            <DropdownMenu>
                                <DropdownMenuTrigger asChild>
                                    <Button variant="ghost" className="h-8 w-8 p-0">
                                        <MoreVertical className="h-4 w-4" />
                                    </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent align="end">
                                    <DropdownMenuItem onClick={handleToggleCompletion}>
                                        {path.is_completed ? <><CheckCircle2 className="mr-2 h-4 w-4" /> Mark as Incomplete</> : <><CheckCircle className="mr-2 h-4 w-4" /> Mark as Completed</>}
                                    </DropdownMenuItem>
                                    <DropdownMenuItem asChild>
                                        <Link href={`/dashboard/paths/${path.id}/edit`} className="w-full cursor-pointer">
                                            <Pencil className="mr-2 h-4 w-4" />
                                            Edit
                                        </Link>
                                    </DropdownMenuItem>
                                    <DropdownMenuItem
                                        onClick={(e) => {
                                            e.stopPropagation()
                                            setIsMoveOpen(true)
                                        }}
                                    >
                                        <FolderInput className="mr-2 h-4 w-4" />
                                        Move to Collection
                                    </DropdownMenuItem>
                                    <DropdownMenuItem
                                        className="text-red-600 focus:text-red-600"
                                        onClick={(e) => {
                                            e.stopPropagation()
                                            setIsDeleteOpen(true)
                                        }}
                                        disabled={isPending}
                                    >
                                        <Trash2 className="mr-2 h-4 w-4" />
                                        Delete
                                    </DropdownMenuItem>
                                </DropdownMenuContent>
                            </DropdownMenu>
                        </div>
                        <CardTitle className={cn("text-lg leading-tight line-clamp-2", path.is_completed && "line-through text-muted-foreground")}>
                            {path.title}
                        </CardTitle>
                        <CardDescription className="text-xs">
                            {format(new Date(path.created_at), 'PPP')}
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="p-4 pt-2 flex-1 space-y-4">
                        <p className="text-sm text-muted-foreground line-clamp-3">
                            {path.description || 'No description available.'}
                        </p>
                        {path.links && path.links.length > 0 && (
                            <div className="space-y-1">
                                <p className="text-xs font-semibold text-muted-foreground uppercase">Resources:</p>
                                <ul className="text-sm space-y-1">
                                    {path.links.slice(0, 3).map((link, i) => (
                                        <li key={i} className="flex items-center gap-2 truncate min-w-0">
                                            <ExternalLink className="h-3 w-3 flex-shrink-0" />
                                            <a href={link} target="_blank" rel="noopener noreferrer" className="hover:underline truncate text-blue-600">
                                                {link}
                                            </a>
                                        </li>
                                    ))}
                                    {path.links.length > 3 && (
                                        <li className="text-xs text-muted-foreground pl-5">
                                            + {path.links.length - 3} more
                                        </li>
                                    )}
                                </ul>
                            </div>
                        )}
                    </CardContent>
                    <CardFooter className="p-4 pt-0 flex flex-col sm:flex-row gap-2">
                        <Button variant="outline" className="w-full sm:flex-1 text-xs" asChild>
                            <a href={path.links?.[0] || '#'} target="_blank" rel="noopener noreferrer">
                                Start Learning <BookOpen className="ml-2 h-3 w-3" />
                            </a>
                        </Button>
                        <Button
                            variant={path.is_completed ? "secondary" : "default"}
                            size="icon"
                            className={cn("h-9 w-full sm:w-9", path.is_completed && "text-green-600")}
                            onClick={handleToggleCompletion}
                            title={path.is_completed ? "Mark as Incomplete" : "Mark as Completed"}
                        >
                            {path.is_completed ? <CheckCircle2 className="h-4 w-4" /> : <CheckCircle className="h-4 w-4" />}
                            <span className="sm:hidden ml-2">{path.is_completed ? "Completed" : "Mark Done"}</span>
                        </Button>
                    </CardFooter>
                </SpotlightCard>
            </HoverEffect >

            <ConfirmDeleteDialog
                open={isDeleteOpen}
                onOpenChange={setIsDeleteOpen}
                onConfirm={handleDelete}
                title="Delete Learning Path?"
                description="This will permanently delete this learning path and cannot be undone."
            />

            <MoveToCollectionDialog
                itemId={path.id}
                itemType="path"
                open={isMoveOpen}
                onOpenChange={setIsMoveOpen}
            />
        </>
    )
}

'use client'

import Lottie from 'lottie-react'
import { useState, useEffect } from 'react'

interface LottiePlayerProps {
    src: string | object // URL or JSON object
    loop?: boolean
    autoplay?: boolean
    className?: string
}

export function LottiePlayer({ src, loop = true, autoplay = true, className }: LottiePlayerProps) {
    const [animationData, setAnimationData] = useState<object | null>(null)

    useEffect(() => {
        if (typeof src === 'string') {
            fetch(src)
                .then(res => res.json())
                .then(data => setAnimationData(data))
                .catch(err => console.error("Failed to load Lottie JSON", err))
        } else {
            setAnimationData(src)
        }
    }, [src])

    if (!animationData) return <div className="h-full w-full bg-muted animate-pulse rounded-md" />

    return (
        <div className={className}>
            <Lottie animationData={animationData} loop={loop} autoplay={autoplay} />
        </div>
    )
}

import { Button } from '@/components/ui/button';
import Link from 'next/link';
import { sidebarNavItems } from '@/lib/nav-config';
import { X, ChevronDown, LogOut, Shield, ChevronRight } from 'lucide-react';
import { cn } from '@/lib/utils';
import { usePathname } from 'next/navigation';
import { useEffect, useState } from 'react';
import { signout } from '@/app/login/actions';
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/components/ui/collapsible';
import {
    Drawer,
    DrawerContent,
    DrawerHeader,
    DrawerTitle,
    DrawerDescription
} from '@/components/ui/drawer';

interface CinematicMenuProps {
    open: boolean;
    onClose: () => void;
    user?: any;
    isAdmin?: boolean;
    isTeamOnly?: boolean;
}

export function CinematicMenu({ open, onClose, user, isAdmin, isTeamOnly }: CinematicMenuProps) {
    const pathname = usePathname();
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
    }, []);

    // Prevent body scroll when menu is open
    useEffect(() => {
        if (open) {
            document.body.style.overflow = 'hidden';
            document.body.style.position = 'fixed';
            document.body.style.width = '100%';
        } else {
            document.body.style.overflow = '';
            document.body.style.position = '';
            document.body.style.width = '';
        }
        return () => {
            document.body.style.overflow = '';
            document.body.style.position = '';
            document.body.style.width = '';
        };
    }, [open]);

    if (!mounted) return null;

    return (
        <Drawer open={open} onOpenChange={(val) => !val && onClose()}>
            <DrawerContent className="h-[90vh] flex flex-col rounded-t-[10px] bg-background">
                <DrawerHeader className="px-6 flex flex-row items-center justify-between space-y-0 shrink-0 mb-2 pt-8">
                    <DrawerTitle className="text-xl font-display font-bold tracking-tight">Menu</DrawerTitle>
                    <Button variant="ghost" size="icon" onClick={onClose} className="rounded-full hover:bg-black/5 -mr-2">
                        <X className="h-5 w-5 opacity-70" />
                    </Button>
                </DrawerHeader>

                <div
                    data-vaul-no-drag
                    className="flex-1 overflow-y-auto px-4 pb-10 min-h-0"
                    style={{ WebkitOverflowScrolling: 'touch' }}
                >
                    <div className="space-y-1">
                        {sidebarNavItems.filter(item => {
                            if (isTeamOnly) {
                                return ['Teams', 'Settings'].includes(item.title)
                            }
                            return true
                        }).map((item, i) => (
                            <MenuItem key={item.href} item={item} pathname={pathname} />
                        ))}

                        {isAdmin && (
                            <Button
                                asChild
                                variant="ghost"
                                className={cn(
                                    "w-full justify-start h-12 text-base font-normal mt-2",
                                    pathname === '/dashboard/admin' ? "bg-primary/10 text-primary" : "text-muted-foreground hover:text-foreground hover:bg-accent/50"
                                )}
                            >
                                <Link href="/dashboard/admin">
                                    <Shield className="mr-3 h-5 w-5" />
                                    Admin Dashboard
                                </Link>
                            </Button>
                        )}

                        <div className="my-4 border-t border-border/40" />

                        <form action={signout}>
                            <Button
                                variant="ghost"
                                className="w-full justify-start text-red-500 hover:bg-red-500/10 hover:text-red-500 h-12 text-base font-normal"
                                type="submit"
                            >
                                <LogOut className="mr-3 h-5 w-5" />
                                Sign Out
                            </Button>
                        </form>

                        <div className="h-10" />
                    </div>
                </div>
            </DrawerContent>
        </Drawer>
    );
}

function MenuItem({ item, pathname }: { item: any; pathname: string }) {
    const isActive = pathname === item.href;
    const hasChildren = item.children && item.children.length > 0;
    const isChildActive = hasChildren && item.children.some((child: any) => pathname.startsWith(child.href));
    const [isOpen, setIsOpen] = useState(isChildActive);

    if (hasChildren) {
        return (
            <Collapsible open={isOpen} onOpenChange={setIsOpen} className="space-y-1">
                <CollapsibleTrigger asChild>
                    <Button
                        variant="ghost"
                        className={cn(
                            "w-full justify-between h-12 text-base font-normal group",
                            (isActive || isChildActive) ? "text-primary bg-primary/5" : "text-muted-foreground hover:text-foreground hover:bg-white/5"
                        )}
                    >
                        <div className="flex items-center">
                            <item.icon className={cn("mr-3 h-5 w-5", (isActive || isChildActive) ? "text-primary" : "text-muted-foreground/70")} />
                            {item.title}
                        </div>
                        <ChevronDown className={cn("h-4 w-4 transition-transform duration-200", isOpen && "rotate-180")} />
                    </Button>
                </CollapsibleTrigger>
                <CollapsibleContent className="pl-4 space-y-1">
                    {item.children.map((child: any) => (
                        <Button
                            key={child.href}
                            variant="ghost"
                            asChild
                            className={cn(
                                "w-full justify-start h-10 text-sm font-normal",
                                pathname === child.href ? "text-primary bg-primary/10" : "text-muted-foreground/80 hover:text-foreground hover:bg-white/5"
                            )}
                        >
                            <Link href={child.href}>
                                <child.icon className="mr-3 h-4 w-4" />
                                {child.title}
                            </Link>
                        </Button>
                    ))}
                </CollapsibleContent>
            </Collapsible>
        );
    }

    return (
        <Button
            variant="ghost"
            asChild
            className={cn(
                "w-full justify-start h-12 text-base font-normal",
                isActive ? "bg-primary/10 text-primary" : "text-muted-foreground hover:text-foreground hover:bg-white/5"
            )}
        >
            <Link href={item.href}>
                <item.icon className={cn("mr-3 h-5 w-5", isActive ? "text-primary" : "text-muted-foreground/70")} />
                {item.title}
            </Link>
        </Button>
    );
}

