}

function DockItem({ href, icon, active }: { href: string; icon: React.ReactNode; active: boolean }) {
    return (
        <Link href={href}>
            <div className={cn(
                "flex flex-col items-center justify-center w-12 h-12 rounded-xl transition-all duration-300",
