                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-2xl font-bold font-display">Quick Add</h2>
                            <Button variant="ghost" size="icon" onClick={onClose} className="rounded-full">
                                <X className="h-5 w-5" />
                            </Button>
