    const shards = useMemo(() => [
        { id: 1, top: '15%', left: '5%', size: 'w-32 h-64', rotate: 15, delay: 0, speed: 0.1 },
        { id: 2, top: '60%', left: '85%', size: 'w-48 h-48', rotate: -10, delay: 2, speed: 0.15 },
